import React, { useState, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { generateFlashcardsForTopic } from '../services/geminiService';
import { Flashcard } from '../types';
import { Brain, RotateCw, ChevronLeft, ChevronRight, Wand2, X } from 'lucide-react';

export const Flashcards: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language } = useApp();
  const [cards, setCards] = useState<Flashcard[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [loading, setLoading] = useState(false);
  const [count, setCount] = useState(5);

  const requestId = useRef<number>(0);

  const handleGenerate = async () => {
    if (!selectedUnit) return;

    const id = Date.now();
    requestId.current = id;
    setLoading(true);

    const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
    try {
      const generated = await generateFlashcardsForTopic(topic, language, 'Beginner', count);
      if (requestId.current === id) {
        setCards(generated);
        setCurrentIndex(0);
        setIsFlipped(false);
        setLoading(false);
      }
    } catch (e) {
      if (requestId.current === id) {
        setLoading(false);
      }
    }
  };

  const handleCancel = () => {
    requestId.current = 0;
    setLoading(false);
  };

  if (!selectedUnit) return null;

  return (
    <div className="mt-12 mb-8">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
          <Brain className="text-purple-500" />
          {t('flashcards')}
        </h3>

        {cards.length === 0 && !loading && (
          <div className="flex items-center gap-2">
            <div className="flex items-center bg-gray-100 dark:bg-gray-800 rounded-lg px-2 py-1">
              <span className="text-xs font-semibold text-gray-500 dark:text-gray-400 mr-2">{t('count')}:</span>
              <input 
                type="number" 
                min="3" 
                max="10" 
                value={count} 
                onChange={(e) => setCount(Number(e.target.value))}
                className="w-12 bg-transparent text-sm font-bold text-gray-900 dark:text-white outline-none"
              />
            </div>
            <button 
              onClick={handleGenerate}
              className="flex items-center gap-2 px-4 py-2 bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 rounded-full font-semibold hover:bg-purple-200 dark:hover:bg-purple-900/50 transition-colors text-sm"
            >
              <Wand2 size={14} />
              {t('generate_flashcards')}
            </button>
          </div>
        )}

        {loading && (
          <button 
            onClick={handleCancel}
            className="flex items-center gap-2 px-4 py-2 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full font-semibold hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors text-sm"
          >
            <X size={14} />
            {t('cancel')}
          </button>
        )}
      </div>

      {loading ? (
        <div className="h-64 flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-800/50 rounded-3xl border border-gray-100 dark:border-gray-800">
           <div className="w-10 h-10 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4" />
           <p className="text-gray-500 dark:text-gray-400 animate-pulse">Generating cards...</p>
        </div>
      ) : cards.length > 0 ? (
        <div className="flex flex-col items-center">
          <div 
            className="perspective-1000 w-full max-w-2xl h-80 cursor-pointer"
            onClick={() => setIsFlipped(!isFlipped)}
          >
            <div className={`relative w-full h-full transition-transform duration-500 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
              {/* Front */}
              <div className="absolute w-full h-full backface-hidden bg-white dark:bg-gray-800 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-700 p-8 flex flex-col items-center justify-center text-center">
                <span className="absolute top-6 left-6 text-xs font-bold text-gray-400 uppercase tracking-wider">Question</span>
                <p className="text-2xl font-medium text-gray-900 dark:text-white leading-relaxed">
                  {cards[currentIndex].front}
                </p>
                <div className="absolute bottom-6 text-gray-400 text-sm flex items-center gap-2">
                  <RotateCw size={14} /> Click to flip
                </div>
              </div>

              {/* Back */}
              <div className="absolute w-full h-full backface-hidden bg-gradient-to-br from-purple-600 to-blue-600 rounded-3xl shadow-xl p-8 flex flex-col items-center justify-center text-center rotate-y-180 text-white">
                <span className="absolute top-6 left-6 text-xs font-bold text-white/60 uppercase tracking-wider">Answer</span>
                <p className="text-xl font-medium leading-relaxed">
                  {cards[currentIndex].back}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6 mt-8">
            <button 
              onClick={() => {
                setIsFlipped(false);
                setCurrentIndex(prev => (prev === 0 ? cards.length - 1 : prev - 1));
              }}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:scale-110 transition-transform"
            >
              <ChevronLeft size={20} className="dark:text-white" />
            </button>

            <span className="font-mono text-sm text-gray-500 dark:text-gray-400">
              {currentIndex + 1} / {cards.length}
            </span>

            <button 
              onClick={() => {
                setIsFlipped(false);
                setCurrentIndex(prev => (prev === cards.length - 1 ? 0 : prev + 1));
              }}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:scale-110 transition-transform"
            >
              <ChevronRight size={20} className="dark:text-white" />
            </button>
          </div>
        </div>
      ) : (
        <div className="h-64 flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-800/50 rounded-3xl border border-dashed border-gray-200 dark:border-gray-700">
           <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center text-gray-400 mb-4">
             <Brain size={24} />
           </div>
           <p className="text-gray-500 dark:text-gray-400 text-center max-w-sm px-4">
             Click "Generate Cards" to create AI-powered flashcards for this unit.
           </p>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { ChatMessage, Flashcard, Unit, Question, QuestionType, Video } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize safely
let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

// Helper to get full language name
const getLanguageName = (code: string) => {
  const map: Record<string, string> = {
    en: "English",
    es: "Spanish",
    fr: "French",
    de: "German",
    zh: "Chinese (Simplified)",
    vi: "Vietnamese",
    it: "Italian",
    hi: "Hindi",
    ar: "Arabic",
    ja: "Japanese",
    ko: "Korean",
    pt: "Portuguese",
    ru: "Russian",
    tr: "Turkish"
  };
  return map[code] || "English";
}

export const generateChatResponse = async (
  history: ChatMessage[], 
  currentMessage: string, 
  context: string,
  languageCode: string = 'en'
): Promise<string> => {
  if (!ai) return "API Key not configured.";

  const lang = getLanguageName(languageCode);

  try {
    const model = ai.models;
    const response = await model.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context: You are a friendly, expert tutor. The user is currently studying: ${context}.

      User History: ${JSON.stringify(history.slice(-5))}

      User Question: ${currentMessage}

      Instructions:
      1. Provide a concise, helpful explanation in ${lang}.
      2. Use Markdown for formatting. 
      3. STRICT UI RENDERING RULES (Prevent Broken UI):
         - Inline code (\`...\`) is ONLY for identifiers or expressions longer than one character (e.g. print() or file.ext).
         - NEVER format single characters or punctuation as code.
         - The following must NEVER appear as code (inline or block): : ; ( ) { } [ ] = => + - * /
         - Code blocks (\`\`\`...\`\`\`) are ONLY for multi-line examples.
         - A code block MUST contain at least one newline.
         - A code block MUST contain at least one letter or digit.
         - A code block MUST show a complete, meaningful example.
         - NEVER place a single symbol, operator, or token inside a code block.
         - Prohibited behavior:
           - Do NOT isolate symbols on their own line.
           - Do NOT “demonstrate” syntax by showing only punctuation.
           - Do NOT use a code block unless the example would compile or run if copied.
         - Explanation rules:
           - When explaining syntax such as colons, arrows, or brackets, explain them in plain text sentences.
           - Use words, not symbols, when possible.
         - Formatting rules:
           - Inline code: single backticks.
           - Code blocks: triple backticks with a language tag.
           - If a choice is ambiguous, prefer plain text over code.
      4. Keep it encouraging and clean.
      5. Ensure all information included is correct and up-to-date.`,
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Sorry, I encountered an error connecting to the AI.";
  }
};

export const generateFlashcardsForTopic = async (
  topic: string, 
  languageCode: string, 
  difficulty: string,
  count: number = 5
): Promise<Flashcard[]> => {
  if (!ai) return [{ front: "API Key Missing", back: "Please check metadata.json" }];

  const lang = getLanguageName(languageCode);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate ${count} educational flashcards for the topic: "${topic}". 
      Target audience: ${difficulty} level.
      Output Language: ${lang}.

      Return ONLY a JSON array of objects with "front" (question/concept) and "back" (answer/explanation) properties.
      Ensure the content is in ${lang}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ['front', 'back']
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Flashcard Gen Error:", error);
    return [{ front: "Error", back: "Could not generate cards." }];
  }
};

export const generateSyllabus = async (
  courseName: string,
  level: string,
  focus: string = "general",
  languageCode: string = "en"
): Promise<Unit[]> => {
  if (!ai) return [];

  const lang = getLanguageName(languageCode);

  // Special handling if course is 'Other' or 'Custom'
  const isCustom = courseName.toLowerCase().includes('custom') || courseName.toLowerCase().includes('other');
  const promptContext = isCustom 
    ? `Create a syllabus of 5 units for learning the topic: "${focus}". Level: ${level}.` 
    : `Create a syllabus of 5 units for learning ${courseName} at a ${level} level. Focus area: ${focus}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `${promptContext}
      Output Language: ${lang}.

      Return a JSON array of objects with 'id', 'title', 'content' (empty string), and 'questions' (empty array).
      The 'id' should be unique-ish (e.g., 'unit_1').`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              title: { type: Type.STRING },
              content: { type: Type.STRING }, // Initial empty
              questions: { type: Type.ARRAY, items: { type: Type.STRING } } // Initial empty
            },
            required: ['id', 'title']
          }
        }
      }
    });

    const units = JSON.parse(response.text || "[]");
    // Ensure structure
    return units.map((u: any, i: number) => ({
      id: `${courseName}_${level}_${i}_${Date.now()}`,
      title: u.title,
      content: "",
      questions: []
    }));

  } catch (error) {
    console.error("Syllabus Gen Error:", error);
    return [];
  }
};

export const generateUnitContent = async (
  courseName: string,
  unitTitle: string,
  level: string,
  languageCode: string = "en",
  quizConfig: { count: number; types: QuestionType[] } = { count: 3, types: ['mcq'] }
): Promise<{ content: string; questions: Question[] }> => {
  if (!ai) return { content: "Error loading content.", questions: [] };

  const lang = getLanguageName(languageCode);
  const typeStr = quizConfig.types.join(', ');

  try {
    // Split into two parallel requests to avoid token limits/truncation issues with large JSON responses
    const [contentResponse, quizResponse] = await Promise.all([
      // 1. Generate Lesson Content (Text/Markdown)
      ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Write a comprehensive, engaging educational lesson for ${courseName} (${level}) on the topic: "${unitTitle}".
        Output Language: ${lang}.

        Formatting Requirements:
        1. Use Markdown.
        2. STRUCTURE IS IMPORTANT: Use H2 headers (##) and H3 headers (###) frequently to break up sections.
        3. Use bullet points for lists.
        4. Use bold text for key terms.
        5. STRICT UI RENDERING RULES (Prevent Broken UI):
           - Inline code (\`...\`) is ONLY for identifiers or expressions longer than one character (e.g. print() or file.ext).
           - NEVER format single characters or punctuation as code.
           - The following must NEVER appear as code (inline or block): : ; ( ) { } [ ] = => + - * /
           - Code blocks (\`\`\`...\`\`\`) are ONLY for multi-line examples.
           - A code block MUST contain at least one newline.
           - A code block MUST contain at least one letter or digit.
           - A code block MUST show a complete, meaningful example.
           - NEVER place a single symbol, operator, or token inside a code block.
           - Prohibited behavior:
             - Do NOT isolate symbols on their own line.
             - Do NOT “demonstrate” syntax by showing only punctuation.
             - Do NOT use a code block unless the example would compile or run if copied.
           - Explanation rules:
             - When explaining syntax such as colons, arrows, or brackets, explain them in plain text sentences.
             - Use words, not symbols, when possible.
           - Formatting rules:
             - Inline code: single backticks.
             - Code blocks: triple backticks with a language tag.
             - If a choice is ambiguous, prefer plain text over code.
        6. Explain concepts clearly with examples, avoiding massive walls of text.`,
      }),

      // 2. Generate Quiz Questions (JSON)
      ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate ${quizConfig.count} quiz questions for ${courseName} (${level}) on topic "${unitTitle}".
        Allowed Question Types: ${typeStr}.
        Output Language: ${lang}.
        IMPORTANT: The 'text', 'options', 'answer', and 'pairs' MUST be in ${lang}. However, keep specific code syntax or keywords in English/Code format if required.`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              questions: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    id: { type: Type.STRING },
                    type: { type: Type.STRING },
                    text: { type: Type.STRING },
                    options: { type: Type.ARRAY, items: { type: Type.STRING } },
                    correctIndex: { type: Type.INTEGER },
                    answer: { type: Type.STRING },
                    pairs: { 
                      type: Type.ARRAY, 
                      items: {
                        type: Type.OBJECT,
                        properties: {
                          term: { type: Type.STRING },
                          definition: { type: Type.STRING }
                        }
                      } 
                    }
                  },
                  required: ['text', 'type']
                }
              }
            },
            required: ['questions']
          }
        }
      })
    ]);

    const contentText = contentResponse.text || "No content generated.";
    const quizJson = JSON.parse(quizResponse.text || "{\"questions\": []}");

    // Add IDs if missing
    const questions = (quizJson.questions || []).map((q: any, i: number) => ({
      ...q,
      id: q.id || `q_${Date.now()}_${i}`
    }));

    return {
      content: contentText,
      questions: questions
    };

  } catch (error) {
    console.error("Unit Content Gen Error:", error);
    return {
      content: "Failed to generate content. Please try again.",
      questions: []
    };
  }
};

