  const toggleChat = () => setIsOpen(!isOpen);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const context = selectedUnit 
      ? `Course: ${selectedCourse?.name}, Unit: ${selectedUnit.title}, Content: ${selectedUnit.content.substring(0, 100)}...`
      : "General Programming";

    // Pass language to generateChatResponse
    const responseText = await generateChatResponse(messages, userMsg.text, context, language);

    const botMsg: ChatMessage = { role: 'model', text: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setLoading(false);
