                      </button>
                      {showFrqAnswers[q.id] && (
                        <div className="mt-4 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl text-green-800 dark:text-green-300 text-sm">
                          <strong>{t('model_answer')}:</strong> {q.answer}
                        </div>
                      )}
                    </div>
                  );
                }

                // RENDER MATCHING
                if (q.type === 'matching' && q.pairs) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text || t('match_pairs')}
                      </h4>
                      <div className="space-y-4">
                        {q.pairs.map((pair, pIdx) => {
                          const currentAnswer = matchingAnswers[q.id]?.[pair.term];
                          const isCorrect = quizSubmitted && currentAnswer === pair.definition;

                          return (
                            <div key={pIdx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-3 bg-gray-50 dark:bg-gray-700/30 rounded-xl">
                              <div className="flex-1 font-semibold text-gray-800 dark:text-gray-200">{pair.term}</div>
                              <div className="hidden sm:block text-gray-400">→</div>
                              <select 
                                value={currentAnswer || ""}
                                onChange={(e) => handleMatchingAnswer(q.id, pair.term, e.target.value)}
                                disabled={quizSubmitted}
                                className={`flex-1 p-2.5 rounded-lg border text-sm outline-none transition-colors ${
                                  quizSubmitted 
                                    ? (isCorrect 
                                        ? "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/40 dark:text-green-200"
                                        : "bg-red-50 border-red-300 text-red-800 dark:bg-red-900/20 dark:text-red-200")
                                    : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-white focus:border-blue-500"
                                }`}
                              >
                                <option value="">{t('select_match')}</option>
                                {/* Shuffle options for display in a real app, here simplifying by showing all definitions */}
                                {q.pairs?.map((p) => (
                                  <option key={p.definition} value={p.definition}>{p.definition}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                }
                return null;
            })
          )}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? t('submit') : t('submit')}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || selectedUnit.questions.length === 0}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}

      {activeTab === 'videos' && (
        <div className="max-w-4xl mx-auto">
          {loadingVideos ? (
             <div className="flex flex-col items-center justify-center py-20">
               <div className="w-12 h-12 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-4" />
               <p className="text-gray-500">{t('searching_videos')}</p>
             </div>
          ) : videos.length === 0 ? (
             <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700">
                <AlertTriangle className="mx-auto h-12 w-12 text-yellow-500 mb-4" />
                <h3 className="text-xl font-bold dark:text-white mb-2">{t('unable_to_find_videos')}</h3>
             </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {videos.map((video) => (
                <div key={video.videoId} className="bg-white dark:bg-gray-800 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden hover:shadow-lg transition-shadow">
                  <div className="aspect-video w-full bg-black relative group">
                    <iframe
                      width="100%"
                      height="100%"
                      src={`https://www.youtube-nocookie.com/embed/${video.videoId}?rel=0&modestbranding=1&playsinline=1&enablejsapi=1&origin=${window.location.origin}`}
                      title={video.title}
                      frameBorder="0"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      referrerPolicy="no-referrer"
                      allowFullScreen
                    ></iframe>
                  </div>
                  <div className="p-5">
                    <h3 className="font-bold text-gray-900 dark:text-white mb-2 line-clamp-2">{video.title}</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-3 mb-4">{video.description}</p>
                    <a 
                      href={`https://www.youtube.com/watch?v=${video.videoId}`} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-2 text-xs font-semibold text-blue-600 dark:text-blue-400 hover:underline"
                    >
                      <ExternalLink size={14} />
                      Watch on YouTube
                    </a>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";
import { ChatMessage, Flashcard, Unit, Question, QuestionType, Video } from "../types";

const API_KEY = process.env.API_KEY || '';

// Initialize safely
let ai: GoogleGenAI | null = null;
if (API_KEY) {
  ai = new GoogleGenAI({ apiKey: API_KEY });
}

// Helper to get full language name
const getLanguageName = (code: string) => {
  const map: Record<string, string> = {
    en: "English",
    es: "Spanish",
    fr: "French",
    de: "German",
    zh: "Chinese (Simplified)",
    vi: "Vietnamese",
    it: "Italian",
    hi: "Hindi",
    ar: "Arabic",
    ja: "Japanese",
    ko: "Korean",
    pt: "Portuguese",
    ru: "Russian",
    tr: "Turkish"
  };
  return map[code] || "English";
}

export const generateChatResponse = async (
  history: ChatMessage[], 
  currentMessage: string, 
  context: string,
  languageCode: string = 'en'
): Promise<string> => {
  if (!ai) return "API Key not configured.";

  const lang = getLanguageName(languageCode);

  try {
    const model = ai.models;
    const response = await model.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Context: You are a friendly, expert tutor. The user is currently studying: ${context}.

      User History: ${JSON.stringify(history.slice(-5))}

      User Question: ${currentMessage}

      Instructions:
      1. Provide a concise, helpful explanation in ${lang}.
      2. Use Markdown for formatting. 
      3. STRICT UI RENDERING RULES (Prevent Broken UI):
         - Inline code (\`...\`) is ONLY for identifiers or expressions longer than one character (e.g. print() or file.ext).
         - CRITICAL: Simple types like 'string', 'number', 'boolean', 'int', 'float', 'void' MUST be formatted as inline code (\`string\`), NEVER as code blocks.
         - NEVER format single characters or punctuation as code.
         - The following must NEVER appear as code (inline or block): : ; ( ) { } [ ] = => + - * /
         - Code blocks (\`\`\`...\`\`\`) are ONLY for multi-line examples.
         - A code block MUST contain at least one newline.
         - A code block MUST contain at least one letter or digit.
         - A code block MUST show a complete, meaningful example.
         - NEVER place a single symbol, operator, or token inside a code block.
         - Prohibited behavior:
           - Do NOT isolate symbols on their own line.
           - Do NOT “demonstrate” syntax by showing only punctuation.
           - Do NOT use a code block unless the example would compile or run if copied.
         - Explanation rules:
           - When explaining syntax such as colons, arrows, or brackets, explain them in plain text sentences.
           - Use words, not symbols, when possible.
         - Formatting rules:
           - Inline code: single backticks.
           - Code blocks: triple backticks with a language tag.
           - If a choice is ambiguous, prefer plain text over code.
      4. Keep it encouraging and clean.
      5. Ensure all information included is correct and up-to-date.`,
    });

    return response.text || "I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error:", error);
    return "Sorry, I encountered an error connecting to the AI.";
  }
};

export const generateFlashcardsForTopic = async (
  topic: string, 
  languageCode: string, 
  difficulty: string,
  count: number = 5
): Promise<Flashcard[]> => {
  if (!ai) return [{ front: "API Key Missing", back: "Please check metadata.json" }];

  const lang = getLanguageName(languageCode);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate ${count} educational flashcards for the topic: "${topic}". 
      Target audience: ${difficulty} level.
      Output Language: ${lang}.

      Return ONLY a JSON array of objects with "front" (question/concept) and "back" (answer/explanation) properties.
      Ensure the content is in ${lang}.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ['front', 'back']
          }
        }
      }
    });

    const jsonText = response.text || "[]";
    return JSON.parse(jsonText);
  } catch (error) {
    console.error("Flashcard Gen Error:", error);
    return [{ front: "Error", back: "Could not generate cards." }];
  }
};

export const generateSyllabus = async (
  courseName: string,
  level: string,
  focus: string = "general",
  languageCode: string = "en"
): Promise<Unit[]> => {
  if (!ai) return [];

  const lang = getLanguageName(languageCode);

  // Special handling if course is 'Other' or 'Custom'
  const isCustom = courseName.toLowerCase().includes('custom') || courseName.toLowerCase().includes('other');
  const promptContext = isCustom 
    ? `Create a syllabus of 5 units for learning the topic: "${focus}". Level: ${level}.` 
    : `Create a syllabus of 5 units for learning ${courseName} at a ${level} level. Focus area: ${focus}.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `${promptContext}
      Output Language: ${lang}.

      Return a JSON array of objects with 'id', 'title', 'content' (empty string), and 'questions' (empty array).
      The 'id' should be unique-ish (e.g., 'unit_1').`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              title: { type: Type.STRING },
              content: { type: Type.STRING }, // Initial empty
              questions: { type: Type.ARRAY, items: { type: Type.STRING } } // Initial empty
            },
            required: ['id', 'title']
          }
        }
      }
    });

    const units = JSON.parse(response.text || "[]");
    // Ensure structure
    return units.map((u: any, i: number) => ({
      id: `${courseName}_${level}_${i}_${Date.now()}`,
      title: u.title,
      content: "",
      questions: []
    }));

  } catch (error) {
    console.error("Syllabus Gen Error:", error);
    return [];
  }
};

export const generateUnitContent = async (
  courseName: string,
  unitTitle: string,
  level: string,
  languageCode: string = "en",
  quizConfig: { count: number; types: QuestionType[] } = { count: 3, types: ['mcq'] },
  focus: string = "",
  onProgress?: (partialContent: string) => void
): Promise<{ content: string; questions: Question[] }> => {
  if (!ai) return { content: "Error loading content.", questions: [] };

  const lang = getLanguageName(languageCode);
  const typeStr = quizConfig.types.join(', ');

  try {
    // Start Quiz generation in parallel (Promise)
    const quizPromise = ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Generate ${quizConfig.count} quiz questions for ${courseName} (${level}) on topic "${unitTitle}".
      Allowed Question Types: ${typeStr}.
      Output Language: ${lang}.
      IMPORTANT: The 'text', 'options', 'answer', and 'pairs' MUST be in ${lang}. However, keep specific code syntax or keywords in English/Code format if required.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            questions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  type: { type: Type.STRING },
                  text: { type: Type.STRING },
                  options: { type: Type.ARRAY, items: { type: Type.STRING } },
                  correctIndex: { type: Type.INTEGER },
                  answer: { type: Type.STRING },
                  pairs: { 
                    type: Type.ARRAY, 
                    items: {
                      type: Type.OBJECT,
                      properties: {
                        term: { type: Type.STRING },
                        definition: { type: Type.STRING }
                      }
                    } 
                  }
                },
                required: ['text', 'type']
              }
            }
          },
          required: ['questions']
        }
      }
    });

    // Start Content generation (Streaming)
    const contentStreamResponse = await ai.models.generateContentStream({
      model: 'gemini-3-flash-preview',
      contents: `Write a comprehensive, engaging educational lesson for ${courseName} (${level}) on the topic: "${unitTitle}".
      ${focus ? `Focus primarily on: ${focus}` : ''}
      Output Language: ${lang}.

      Formatting Requirements:
      1. Use Markdown.
      2. STRUCTURE IS IMPORTANT: Use H2 headers (##) and H3 headers (###) frequently to break up sections.
      3. Use bullet points for lists.
      4. Use bold text for key terms.
      5. STRICT UI RENDERING RULES (Prevent Broken UI):
          - Inline code (\`...\`) is ONLY for identifiers or expressions longer than one character (e.g. print() or file.ext).
          - CRITICAL: Simple types like 'string', 'number', 'boolean', 'int', 'float', 'void' MUST be formatted as inline code (\`string\`), NEVER as code blocks.
          - NEVER format single characters or punctuation as code.
          - The following must NEVER appear as code (inline or block): : ; ( ) { } [ ] = => + - * /
          - Code blocks (\`\`\`...\`\`\`) are ONLY for multi-line examples.
          - A code block MUST contain at least one newline.
          - A code block MUST contain at least one letter or digit.
          - A code block MUST show a complete, meaningful example.
          - NEVER place a single symbol, operator, or token inside a code block.
          - Prohibited behavior:
            - Do NOT isolate symbols on their own line.
            - Do NOT “demonstrate” syntax by showing only punctuation.
            - Do NOT use a code block unless the example would compile or run if copied.
          - Explanation rules:
            - When explaining syntax such as colons, arrows, or brackets, explain them in plain text sentences.
            - Use words, not symbols, when possible.
          - Formatting rules:
            - Inline code: single backticks.
            - Code blocks: triple backticks with a language tag.
            - If a choice is ambiguous, prefer plain text over code.
      6. Explain concepts clearly with examples, avoiding massive walls of text.`,
    });

    let fullContentText = "";

    // Process stream
    for await (const chunk of contentStreamResponse) {
      const chunkText = (chunk as GenerateContentResponse).text;
      if (chunkText) {
        fullContentText += chunkText;
        if (onProgress) {
          onProgress(fullContentText);
        }
      }
    }

    // Await quiz response after content is done (or it might already be done)
    const quizResponse = await quizPromise;
    const quizJson = JSON.parse(quizResponse.text || "{\"questions\": []}");

    // Add IDs if missing
    const questions = (quizJson.questions || []).map((q: any, i: number) => ({
      ...q,
      id: q.id || `q_${Date.now()}_${i}`
    }));

    return {
      content: fullContentText,
      questions: questions
    };

  } catch (error) {
    console.error("Unit Content Gen Error:", error);
    return {
      content: "Failed to generate content. Please try again.",
      questions: []
    };
  }
};

export const fetchVideos = async (
  topic: string, 
  languageCode: string
): Promise<Video[]> => {
  if (!ai) return [];

  const lang = getLanguageName(languageCode);

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Find 3 helpful YouTube video tutorials for the topic: "${topic}".
      Language: ${lang}.

      Instructions:
      1. Use Google Search to find video IDs.
      2. Prefer official tutorials or high-quality educational channels that allow embedding.
      3. Return ONLY a JSON object.

      JSON Schema:
      {
        "videos": [
          { "title": "string", "videoId": "string (11 char ID ONLY)", "description": "short string" }
        ]
      }`,
      config: {
        tools: [{googleSearch: {}}],
        responseMimeType: "application/json"
      }
    });

    const jsonText = response.text || "{}";
    const data = JSON.parse(jsonText);

    // Robust ID extraction/sanitization
    const videos = (data.videos || []).map((v: any) => {
      // If the AI returns a full URL, extract the ID
      let id = v.videoId;
      if (id.length > 11) {
        const match = id.match(/(?:youtu\.be\/|youtube\.com\/(?:embed\/|v\/|watch\?v=|watch\?.+&v=))([^&?]+)/);
        if (match) id = match[1];
      }
      return { ...v, videoId: id };
    });

    return videos;
  } catch (error) {
    console.error("Fetch Videos Error:", error);
    return [];
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { Flashcards } from './Flashcards';
import { generateUnitContent, fetchVideos } from '../services/geminiService';
import { ArrowLeft, CheckCircle, AlertCircle, Eye, SlidersHorizontal, Play, Youtube, AlertTriangle, ExternalLink, X, RotateCcw } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { QuestionType, Video } from '../types';

export const UnitView: React.FC = () => {
  const { selectedUnit, selectedCourse, selectedLevel, selectUnit, updateUnitContent, t, language } = useApp();
  const [activeTab, setActiveTab] = useState<'learn' | 'quiz' | 'videos'>('learn');
  const [loading, setLoading] = useState(false);
  const [videos, setVideos] = useState<Video[]>([]);
  const [loadingVideos, setLoadingVideos] = useState(false);
  const [videosFetched, setVideosFetched] = useState(false);

  // Request Cancellation Tracking
  const generationRequestId = useRef<number>(0);

  // Quiz State
  const [selectedAnswers, setSelectedAnswers] = useState<Record<string, number>>({}); // For MCQ
  const [matchingAnswers, setMatchingAnswers] = useState<Record<string, Record<string, string>>>({}); // For Matching: qId -> term -> selectedDefinition
  const [showFrqAnswers, setShowFrqAnswers] = useState<Record<string, boolean>>({}); // For FRQ
  const [quizSubmitted, setQuizSubmitted] = useState(false);

  // Configuration State
  const [configMode, setConfigMode] = useState(!selectedUnit?.content);
  const [quizCount, setQuizCount] = useState(3);
  const [selectedTypes, setSelectedTypes] = useState<QuestionType[]>(['mcq']);
  const [unitFocus, setUnitFocus] = useState('');

  useEffect(() => {
    // Reset video state when unit changes
    setVideos([]);
    setVideosFetched(false);
    setActiveTab('learn');
    setUnitFocus('');
  }, [selectedUnit?.id]);

  useEffect(() => {
    if (activeTab === 'videos' && !videosFetched && selectedUnit) {
      const loadVideos = async () => {
        setLoadingVideos(true);
        const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
        const results = await fetchVideos(topic, language);
        setVideos(results);
        setVideosFetched(true);
        setLoadingVideos(false);
      };
      loadVideos();
    }
  }, [activeTab, selectedUnit, videosFetched, selectedCourse, language]);

  const handleStartLesson = async () => {
    if (selectedUnit && selectedCourse && selectedLevel) {
      const requestId = Date.now();
      generationRequestId.current = requestId;

      // Immediately switch to content view and show loading state
      setConfigMode(false);
      setLoading(true);

      try {
        const data = await generateUnitContent(
          selectedCourse.name, 
          selectedUnit.title, 
          selectedLevel.id, 
          language,
          { count: quizCount, types: selectedTypes },
          unitFocus,
          (partialContent) => {
            // Streaming callback
            if (generationRequestId.current === requestId) {
               // If this is the first chunk, stop loading spinner
               setLoading((prev) => {
                 if (prev) return false;
                 return prev;
               });
               // Update content in real-time
               updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, partialContent, []);
            }
          }
        );

        // Only update if this request is still the active one
        if (generationRequestId.current === requestId) {
          updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, data.content, data.questions);
          setLoading(false);
        }
      } catch (e) {
        if (generationRequestId.current === requestId) {
          setLoading(false);
          // Optionally revert config mode or show error
          setConfigMode(true);
        }
      }
    }
  };

  const handleCancelGeneration = () => {
    // Invalidate current request
    generationRequestId.current = 0;
    setLoading(false);
    // Go back to config mode
    setConfigMode(true);
  };

  const handleRegenerate = () => {
    if (selectedCourse && selectedLevel && selectedUnit) {
       // Clear current content effectively resetting to "not generated" state
       updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, "", []);
       // Explicitly switch to config mode
       setConfigMode(true);
    }
  };

  const toggleType = (type: QuestionType) => {
    setSelectedTypes(prev => {
      if (prev.includes(type) && prev.length > 1) {
        return prev.filter(t => t !== type);
      } else if (!prev.includes(type)) {
        return [...prev, type];
      }
      return prev;
    });
  };

  const submitQuiz = () => {
    setQuizSubmitted(true);
  };

  if (!selectedUnit) return null;

  if (loading) {
     return (
        <div className="min-h-[50vh] flex flex-col items-center justify-center animate-fade-in px-4">
           <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6" />
           <h2 className="text-xl font-bold dark:text-white mb-2">{t('generating_lesson')}</h2>
           <p className="text-gray-500 text-center max-w-md mb-8">{t('crafting_lesson')} {selectedUnit.title}</p>

           <button 
             onClick={handleCancelGeneration}
             className="flex items-center gap-2 px-6 py-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full font-semibold hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors"
           >
             <X size={18} />
             {t('cancel')}
           </button>
        </div>
     )
  }

  // Initial Configuration Screen
  if (configMode) {
    return (
      <div className="max-w-xl mx-auto pt-10 animate-fade-in">
        <button 
          onClick={() => selectUnit(null)} 
          className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
        >
          <ArrowLeft size={16} /> {t('back')}
        </button>

        <div className="bg-white dark:bg-gray-900 rounded-3xl p-8 shadow-xl border border-gray-100 dark:border-gray-800">
          <div className="w-14 h-14 bg-blue-50 dark:bg-blue-900/20 text-blue-600 rounded-2xl flex items-center justify-center mb-6">
            <SlidersHorizontal size={28} />
          </div>
          <h2 className="text-2xl font-bold dark:text-white mb-2">{t('customize_quiz')}</h2>
          <p className="text-gray-500 dark:text-gray-400 mb-8">{selectedUnit.title}</p>

          <div className="space-y-8">
            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">
                {t('unit_focus_label')}
              </label>
              <input 
                 type="text"
                 value={unitFocus}
                 onChange={(e) => setUnitFocus(e.target.value)}
                 placeholder={t('unit_focus_placeholder')}
                 className="w-full px-4 py-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-2 border-transparent focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white transition-all text-sm"
              />
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-4">
                {t('num_questions')}: <span className="text-blue-600">{quizCount}</span>
              </label>
              <input 
                type="range" 
                min="1" 
                max="10" 
                value={quizCount} 
                onChange={(e) => setQuizCount(parseInt(e.target.value))}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700 accent-blue-600"
              />
              <div className="flex justify-between text-xs text-gray-400 mt-2">
                <span>1</span>
                <span>10</span>
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-4">
                {t('question_types')}
              </label>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                {[
                  { id: 'mcq' as const, label: 'MCQ' },
                  { id: 'frq' as const, label: 'Open Ended' },
                  { id: 'matching' as const, label: 'Matching' }
                ].map((type) => (
                  <button
                    key={type.id}
                    onClick={() => toggleType(type.id)}
                    className={`py-3 px-4 rounded-xl border-2 font-medium transition-all ${
                      selectedTypes.includes(type.id)
                        ? 'border-blue-500 bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400'
                        : 'border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 hover:border-gray-300 dark:hover:border-gray-600'
                    }`}
                  >
                    {type.label}
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={handleStartLesson}
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <Play size={20} fill="currentColor" />
              {t('start_lesson')}
            </button>
          </div>
        </div>
      </div>
    );
  }

  const handleMcqAnswer = (qId: string, idx: number) => {
    if (quizSubmitted) return;
    setSelectedAnswers(prev => ({ ...prev, [qId]: idx }));
  };

  const handleMatchingAnswer = (qId: string, term: string, def: string) => {
    if (quizSubmitted) return;
    setMatchingAnswers(prev => ({
      ...prev,
      [qId]: { ...(prev[qId] || {}), [term]: def }
    }));
  };

  return (
    <div className="animate-fade-in pb-20">
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={() => selectUnit(null)} 
          className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
        >
          <ArrowLeft size={16} /> {t('back')}
        </button>

        <button 
          onClick={handleRegenerate}
          className="flex items-center gap-2 px-3 py-1.5 bg-red-50 dark:bg-red-900/10 text-red-600 dark:text-red-400 rounded-lg text-xs font-semibold hover:bg-red-100 dark:hover:bg-red-900/30 transition-colors"
        >
          <RotateCcw size={12} />
          {t('regenerate')}
        </button>
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">
          {selectedUnit.title}
        </h1>
        <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-xl self-start">
          <button
            onClick={() => setActiveTab('learn')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'learn' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('learn')}
          </button>
          <button
            onClick={() => setActiveTab('quiz')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'quiz' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('quiz')}
          </button>
          <button
            onClick={() => setActiveTab('videos')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'videos' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('videos')}
          </button>
        </div>
      </div>

      {activeTab === 'learn' && (
        <div className="max-w-4xl mx-auto">
          <div className="prose prose-lg dark:prose-invert max-w-none">
            <ReactMarkdown 
               components={{
                 // Headers with more spacing
                 h1: ({children}) => <h1 className="text-4xl font-extrabold mt-12 mb-6 text-gray-900 dark:text-white leading-tight">{children}</h1>,
                 h2: ({children}) => <h2 className="text-2xl font-bold mt-12 mb-6 text-gray-800 dark:text-white border-b border-gray-200 dark:border-gray-800 pb-3">{children}</h2>,
                 h3: ({children}) => <h3 className="text-xl font-bold mt-8 mb-4 text-gray-800 dark:text-gray-200">{children}</h3>,

                 // Paragraphs with more line height and spacing
                 p: ({children}) => <p className="text-lg leading-loose mb-6 text-gray-700 dark:text-gray-300">{children}</p>,

                 // Lists with spacing
                 ul: ({children}) => <ul className="list-disc pl-6 mb-6 space-y-3 text-lg text-gray-700 dark:text-gray-300">{children}</ul>,
                 ol: ({children}) => <ol className="list-decimal pl-6 mb-6 space-y-3 text-lg text-gray-700 dark:text-gray-300">{children}</ol>,
                 li: ({children}) => <li className="pl-2">{children}</li>,

                 // Code blocks vs Inline code
                 code: ({node, inline, className, children, ...props}: any) => {
                   // Check for multi-line content
                   const content = String(children).replace(/\n$/, '');
                   const isMultiLine = content.includes('\n');

                   if (inline || !isMultiLine) {
                     // INLINE CODE OR SINGLE LINE BLOCK: Distinct Pill Style
                     // We treat single line blocks as inline-styled to prevent the huge Mac window look
                     return (
                       <code className="bg-indigo-50 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-2 py-0.5 rounded-md text-[0.9em] font-mono border border-indigo-100 dark:border-indigo-800/50 align-middle" {...props}>
                         {children}
                       </code>
                     );
                   }

                   // MULTI-LINE BLOCK CODE: Mac Terminal Style with Spacing
                   return (
                     <div className="my-10 rounded-2xl overflow-hidden shadow-2xl bg-[#1e1e1e] border border-gray-700/50 transform transition-transform hover:scale-[1.01] duration-300">
                       <div className="flex items-center gap-2 px-5 py-3 bg-[#2d2d2d] border-b border-gray-700/50">
                         <div className="w-3 h-3 rounded-full bg-[#ff5f56]" />
                         <div className="w-3 h-3 rounded-full bg-[#ffbd2e]" />
                         <div className="w-3 h-3 rounded-full bg-[#27c93f]" />
                         <div className="ml-auto text-xs text-gray-500 font-mono opacity-50">code</div>
                       </div>
                       <div className="p-6 overflow-x-auto">
                         <code className="font-mono text-sm text-gray-200 leading-relaxed block" {...props}>
                           {children}
                         </code>
                       </div>
                     </div>
                   );
                 },
                 // Blockquotes
                 blockquote: ({children}) => (
                   <blockquote className="border-l-4 border-blue-500 pl-6 py-2 my-8 italic bg-blue-50/50 dark:bg-blue-900/10 rounded-r-xl text-gray-700 dark:text-gray-300">
                     {children}
                   </blockquote>
                 )
               }}
            >
              {selectedUnit.content}
            </ReactMarkdown>
          </div>
          <div className="my-16 border-t border-gray-100 dark:border-gray-800 pt-10">
            <Flashcards />
          </div>
        </div>
      )}

      {activeTab === 'quiz' && (
        <div className="max-w-2xl mx-auto space-y-8">
          {selectedUnit.questions.length === 0 ? (
            <div className="text-center text-gray-500">No questions generated.</div>
          ) : (
             selectedUnit.questions.map((q, idx) => {
                // RENDER MCQ
                if (q.type === 'mcq' && q.options) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <div className="space-y-3">
                        {q.options.map((opt, optIdx) => {
                          let btnClass = "w-full text-left p-4 rounded-xl border transition-all text-sm font-medium ";
                          if (quizSubmitted) {
                            if (optIdx === q.correctIndex) btnClass += "bg-green-100 border-green-500 text-green-700 dark:bg-green-900/30 dark:text-green-300 ";
                            else if (selectedAnswers[q.id] === optIdx) btnClass += "bg-red-50 border-red-200 text-red-600 dark:bg-red-900/20 dark:text-red-300 ";
                            else btnClass += "border-transparent bg-gray-50 dark:bg-gray-700/50 opacity-50 dark:text-gray-400 ";
                          } else {
                            if (selectedAnswers[q.id] === optIdx) btnClass += "border-blue-500 bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300 ";
                            else btnClass += "border-transparent bg-gray-50 hover:bg-gray-100 dark:bg-gray-700/50 dark:hover:bg-gray-700 dark:text-gray-300 ";
                          }
                          return (
                            <button key={optIdx} onClick={() => handleMcqAnswer(q.id, optIdx)} className={btnClass}>
                              <div className="flex items-center justify-between">
                                {opt}
                                {quizSubmitted && optIdx === q.correctIndex && <CheckCircle size={16} className="text-green-600" />}
                                {quizSubmitted && selectedAnswers[q.id] === optIdx && optIdx !== q.correctIndex && <AlertCircle size={16} className="text-red-500" />}
                              </div>
                            </button>
                          )
                        })}
                      </div>
                    </div>
                  );
                }

                // RENDER FRQ
                if (q.type === 'frq') {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <textarea 
                        className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white h-32 mb-4"
                        placeholder={t('type_message')}
                      ></textarea>
                      <button 
                        onClick={() => setShowFrqAnswers(prev => ({...prev, [q.id]: !prev[q.id]}))}
                        className="text-blue-600 dark:text-blue-400 font-semibold text-sm flex items-center gap-2 hover:underline"
                      >
                        <Eye size={16} /> {t('reveal_answer')}
                      </button>
                      {showFrqAnswers[q.id] && (
                        <div className="mt-4 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl text-green-800 dark:text-green-300 text-sm">
                          <strong>{t('model_answer')}:</strong> {q.answer}
                        </div>
                      )}
                    </div>
                  );
                }

                // RENDER MATCHING
                if (q.type === 'matching' && q.pairs) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text || t('match_pairs')}
                      </h4>
                      <div className="space-y-4">
                        {q.pairs.map((pair, pIdx) => {
                          const currentAnswer = matchingAnswers[q.id]?.[pair.term];
                          const isCorrect = quizSubmitted && currentAnswer === pair.definition;

                          return (
                            <div key={pIdx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-3 bg-gray-50 dark:bg-gray-700/30 rounded-xl">
                              <div className="flex-1 font-semibold text-gray-800 dark:text-gray-200">{pair.term}</div>
                              <div className="hidden sm:block text-gray-400">→</div>
                              <select 
                                value={currentAnswer || ""}
                                onChange={(e) => handleMatchingAnswer(q.id, pair.term, e.target.value)}
                                disabled={quizSubmitted}
                                className={`flex-1 p-2.5 rounded-lg border text-sm outline-none transition-colors ${
                                  quizSubmitted 
                                    ? (isCorrect 
                                        ? "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/40 dark:text-green-200"
                                        : "bg-red-50 border-red-300 text-red-800 dark:bg-red-900/20 dark:text-red-200")
                                    : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-white focus:border-blue-500"
                                }`}
                              >
                                <option value="">{t('select_match')}</option>
                                {/* Shuffle options for display in a real app, here simplifying by showing all definitions */}
                                {q.pairs?.map((p) => (
                                  <option key={p.definition} value={p.definition}>{p.definition}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                }
                return null;
            })
          )}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? t('submit') : t('submit')}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || selectedUnit.questions.length === 0}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}

      {activeTab === 'videos' && (
        <div className="max-w-4xl mx-auto">
          {loadingVideos ? (
             <div className="flex flex-col items-center justify-center py-20">
               <div className="w-12 h-12 border-4 border-red-500 border-t-transparent rounded-full animate-spin mb-4" />
               <p className="text-gray-500">{t('searching_videos')}</p>
             </div>
          ) : videos.length === 0 ? (
             <div className="text-center py-20 bg-white dark:bg-gray-800 rounded-3xl border border-gray-100 dark:border-gray-700">
                <AlertTriangle className="mx-auto h-12 w-12 text-yellow-500 mb-4" />
                <h3 className="text-xl font-bold dark:text-white mb-2">{t('unable_to_find_videos')}</h3>
             </div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              {videos.map((video) => (
                <div key={video.videoId} className="bg-white dark:bg-gray-800 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700 overflow-hidden hover:shadow-lg transition-shadow">
                  <div className="aspect-video w-full bg-black relative group">
                    <iframe
                      width="100%"
                      height="100%"
                      src={`https://www.youtube-nocookie.com/embed/${video.videoId}?rel=0&modestbranding=1&playsinline=1&enablejsapi=1&origin=${window.location.origin}`}
                      title={video.title}
                      frameBorder="0"
                      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
                      referrerPolicy="no-referrer"
                      allowFullScreen
                    ></iframe>
                  </div>
                  <div className="p-5">
                    <h3 className="font-bold text-gray-900 dark:text-white mb-2 line-clamp-2">{video.title}</h3>
                    <p className="text-sm text-gray-500 dark:text-gray-400 line-clamp-3 mb-4">{video.description}</p>
                    <a 
                      href={`https://www.youtube.com/watch?v=${video.videoId}`} 
                      target="_blank" 
                      rel="noopener noreferrer"
                      className="inline-flex items-center gap-2 text-xs font-semibold text-blue-600 dark:text-blue-400 hover:underline"
                    >
                      <ExternalLink size={14} />
                      Watch on YouTube
                    </a>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { generateChatResponse } from '../services/geminiService';
import { ChatMessage } from '../types';
import { MessageSquare, Send, Sparkles, X, Minimize2, Maximize2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

export const AIChat: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  const toggleChat = () => setIsOpen(!isOpen);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const context = selectedUnit 
      ? `Course: ${selectedCourse?.name}, Unit: ${selectedUnit.title}, Content: ${selectedUnit.content.substring(0, 100)}...`
      : "General Programming";

    // Pass language to generateChatResponse
    const responseText = await generateChatResponse(messages, userMsg.text, context, language);

    const botMsg: ChatMessage = { role: 'model', text: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={toggleChat}
        className="fixed bottom-6 right-6 w-14 h-14 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full shadow-xl shadow-blue-500/40 flex items-center justify-center text-white hover:scale-110 transition-transform z-40 active:scale-95"
      >
        <Sparkles size={24} />
      </button>
    );
  }

  return (
    <div className={`fixed bottom-6 right-6 w-full md:w-[450px] bg-white dark:bg-gray-900 rounded-3xl shadow-2xl z-40 flex flex-col transition-all duration-300 border border-gray-100 dark:border-gray-800 overflow-hidden ${isMinimized ? 'h-[70px]' : 'h-[650px] max-h-[85vh]'}`}>

      {/* Header */}
      <div className="h-16 bg-white/90 dark:bg-gray-900/90 backdrop-blur-md flex items-center justify-between px-5 border-b border-gray-100 dark:border-gray-800 absolute top-0 left-0 right-0 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
            <Sparkles size={16} />
          </div>
          <div>
            <h3 className="font-bold text-sm dark:text-white">{t('ai_tutor')}</h3>
            {!isMinimized && <p className="text-[10px] text-green-500 font-medium flex items-center gap-1"><span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"/> Online</p>}
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setIsMinimized(!isMinimized)} className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
            {isMinimized ? <Maximize2 size={16} /> : <Minimize2 size={16} />}
          </button>
          <button onClick={toggleChat} className="p-2 text-gray-400 hover:text-red-500">
            <X size={18} />
          </button>
        </div>
      </div>

      {/* Messages */}
      {!isMinimized && (
        <>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 pt-20 pb-4 space-y-4 bg-gray-50/50 dark:bg-black/20">
            {messages.length === 0 && (
              <div className="text-center text-gray-400 mt-20 p-6">
                <MessageSquare size={48} className="mx-auto mb-4 opacity-20" />
                <p className="text-sm">{t('type_message')}</p>
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[90%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm overflow-hidden ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-br-none' 
                    : 'bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-100 dark:border-gray-700 rounded-bl-none'
                }`}>
                  <div className={`prose prose-sm dark:prose-invert max-w-none 
                      ${msg.role === 'user' ? 'prose-headings:text-white prose-p:text-white prose-strong:text-white prose-code:text-white' : ''}
                    `}>
                    <ReactMarkdown 
                      components={{
                        code: ({node, inline, className, children, ...props}: any) => {
                          // Check for multi-line content
                          const content = String(children).replace(/\n$/, '');
                          const isMultiLine = content.includes('\n');

                          if (inline || !isMultiLine) {
                            return (
                              <code className="bg-indigo-50 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-2 py-0.5 rounded-md text-[0.9em] font-mono border border-indigo-100 dark:border-indigo-800/50 align-middle" {...props}>
                                {children}
                              </code>
                            )
                          }
                          // Reuse macOS window style in chat
                          return (
                            <div className="my-2 rounded-lg overflow-hidden shadow-lg bg-[#1e1e1e] border border-gray-700/50 text-left">
                               <div className="flex items-center gap-1.5 px-3 py-2 bg-[#2d2d2d] border-b border-gray-700/50">
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#ff5f56]" />
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#ffbd2e]" />
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#27c93f]" />
                               </div>
                               <div className="p-3 overflow-x-auto">
                                 <code className="font-mono text-xs text-gray-200 leading-relaxed" {...props}>
                                   {children}
                                 </code>
                               </div>
                             </div>
                          )
                        }
                      }}
                    >
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl rounded-bl-none shadow-sm border border-gray-100 dark:border-gray-700">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 bg-white dark:bg-gray-900 border-t border-gray-100 dark:border-gray-800">
            <div className="relative">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder={t('type_message')}
                className="w-full bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-white rounded-full py-3.5 pl-5 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 rounded-full text-white shadow-lg shadow-blue-500/30 disabled:opacity-50 disabled:shadow-none hover:scale-105 active:scale-95 transition-all"
              >
                <Send size={16} />
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

