                          onClick={handleGenerateSyllabus}
                          disabled={generatingSyllabus}
                          className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 transition-all active:scale-95 disabled:opacity-70 flex items-center justify-center gap-2"
                        >
                          <Sparkles size={20} />
                          {t('generate_syllabus')}
                        </button>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </div>

      <AIChat />
      {showSettings && <Settings onClose={() => setShowSettings(false)} />}
    </div>
  );
};

export default function App() {
  return (
    <AppProvider>
      <MainContent />
    </AppProvider>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { Flashcards } from './Flashcards';
import { generateUnitContent, fetchVideos } from '../services/geminiService';
import { ArrowLeft, CheckCircle, AlertCircle, Eye, SlidersHorizontal, Play, Youtube, AlertTriangle, ExternalLink, X, RotateCcw } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { QuestionType, Video } from '../types';

export const UnitView: React.FC = () => {
  const { 
    selectedUnit, selectedCourse, selectedLevel, selectUnit, updateUnitContent, t, language,
    getEffectiveApiKey, isRateLimited, incrementRequestCount, setShowSettings
  } = useApp();

  const [activeTab, setActiveTab] = useState<'learn' | 'quiz' | 'videos'>('learn');
  const [loading, setLoading] = useState(false);
  const [videos, setVideos] = useState<Video[]>([]);
  const [loadingVideos, setLoadingVideos] = useState(false);
  const [videosFetched, setVideosFetched] = useState(false);

  // Request Cancellation Tracking
  const generationRequestId = useRef<number>(0);

  // Quiz State
  const [selectedAnswers, setSelectedAnswers] = useState<Record<string, number>>({}); // For MCQ
  const [matchingAnswers, setMatchingAnswers] = useState<Record<string, Record<string, string>>>({}); // For Matching: qId -> term -> selectedDefinition
  const [showFrqAnswers, setShowFrqAnswers] = useState<Record<string, boolean>>({}); // For FRQ
  const [quizSubmitted, setQuizSubmitted] = useState(false);

  // Configuration State
  const [configMode, setConfigMode] = useState(!selectedUnit?.content);
  const [quizCount, setQuizCount] = useState(3);
  const [selectedTypes, setSelectedTypes] = useState<QuestionType[]>(['mcq']);
  const [unitFocus, setUnitFocus] = useState('');

  useEffect(() => {
    // Reset video state when unit changes
    setVideos([]);
    setVideosFetched(false);
    setActiveTab('learn');
    setUnitFocus('');
  }, [selectedUnit?.id]);

  useEffect(() => {
    if (activeTab === 'videos' && !videosFetched && selectedUnit) {
      if (isRateLimited) {
         setShowSettings(true);
         // Don't auto-fetch if rate limited to avoid loop or error
         return;
      }

      const loadVideos = async () => {
        setLoadingVideos(true);
        const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
        const results = await fetchVideos(getEffectiveApiKey(), topic, language);
        if (results.length > 0) incrementRequestCount();
        setVideos(results);
        setVideosFetched(true);
        setLoadingVideos(false);
      };
      loadVideos();
    }
  }, [activeTab, selectedUnit, videosFetched, selectedCourse, language, isRateLimited, getEffectiveApiKey]);

  const handleStartLesson = async () => {
    if (selectedUnit && selectedCourse && selectedLevel) {
      if (isRateLimited) {
        setShowSettings(true);
        return;
      }

      const requestId = Date.now();
      generationRequestId.current = requestId;

      // Immediately switch to content view and show loading state
      setConfigMode(false);
      setLoading(true);

      try {
        const data = await generateUnitContent(
          getEffectiveApiKey(),
          selectedCourse.name, 
          selectedUnit.title, 
          selectedLevel.id, 
          language,
          { count: quizCount, types: selectedTypes },
          unitFocus,
          (partialContent) => {
            // Streaming callback
            if (generationRequestId.current === requestId) {
               // If this is the first chunk, stop loading spinner
               setLoading((prev) => {
                 if (prev) return false;
                 return prev;
               });
               // Update content in real-time
               updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, partialContent, []);
            }
          }
        );

        // Only update if this request is still the active one
        if (generationRequestId.current === requestId) {
          if (data.questions.length > 0 || data.content) incrementRequestCount();
          updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, data.content, data.questions);
          setLoading(false);
        }
      } catch (e) {
        if (generationRequestId.current === requestId) {
          setLoading(false);
          // Optionally revert config mode or show error
          setConfigMode(true);
        }
      }
    }
  };

  const handleCancelGeneration = () => {
    // Invalidate current request
    generationRequestId.current = 0;
    setLoading(false);
    // Go back to config mode
    setConfigMode(true);
  };

  const handleRegenerate = () => {
    if (selectedCourse && selectedLevel && selectedUnit) {
       // Clear current content effectively resetting to "not generated" state
       updateUnitContent(selectedCourse.id, selectedLevel.id, selectedUnit.id, "", []);
       // Explicitly switch to config mode
       setConfigMode(true);
    }
  };

  const toggleType = (type: QuestionType) => {
    setSelectedTypes(prev => {
      if (prev.includes(type) && prev.length > 1) {
        return prev.filter(t => t !== type);
      } else if (!prev.includes(type)) {
        return [...prev, type];
      }
      return prev;
    });
  };

  const submitQuiz = () => {
    setQuizSubmitted(true);
  };

  if (!selectedUnit) return null;

  if (loading) {
     return (
        <div className="min-h-[50vh] flex flex-col items-center justify-center animate-fade-in px-4">
           <div className="w-16 h-16 border-4 border-blue-500 border-t-transparent rounded-full animate-spin mb-6" />
           <h2 className="text-xl font-bold dark:text-white mb-2">{t('generating_lesson')}</h2>
           <p className="text-gray-500 text-center max-w-md mb-8">{t('crafting_lesson')} {selectedUnit.title}</p>

           <button 
             onClick={handleCancelGeneration}
             className="flex items-center gap-2 px-6 py-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full font-semibold hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors"
           >
             <X size={18} />
             {t('cancel')}
           </button>
        </div>
     )
  }

  // Initial Configuration Screen
  if (configMode) {
    return (
      <div className="max-w-xl mx-auto pt-10 animate-fade-in">
        <button 
          onClick={() => selectUnit(null)} 
          className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
        >
          <ArrowLeft size={16} /> {t('back')}
        </button>

        <div className="bg-white dark:bg-gray-900 rounded-3xl p-8 shadow-xl border border-gray-100 dark:border-gray-800">
          <div className="w-14 h-14 bg-blue-50 dark:bg-blue-900/20 text-blue-600 rounded-2xl flex items-center justify-center mb-6">
            <SlidersHorizontal size={28} />
          </div>
          <h2 className="text-2xl font-bold dark:text-white mb-2">{t('customize_quiz')}</h2>
          <p className="text-gray-500 dark:text-gray-400 mb-8">{selectedUnit.title}</p>

          <div className="space-y-8">
            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-2">
                {t('unit_focus_label')}
              </label>
              <input 
                 type="text"
                 value={unitFocus}
                 onChange={(e) => setUnitFocus(e.target.value)}
                 placeholder={t('unit_focus_placeholder')}
                 className="w-full px-4 py-3 rounded-xl bg-gray-50 dark:bg-gray-800 border-2 border-transparent focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white transition-all text-sm"
              />
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-4">
                {t('num_questions')}: <span className="text-blue-600">{quizCount}</span>
              </label>
              <input 
                type="range" 
                min="1" 
                max="10" 
                value={quizCount} 
                onChange={(e) => setQuizCount(parseInt(e.target.value))}
                className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700 accent-blue-600"
              />
              <div className="flex justify-between text-xs text-gray-400 mt-2">
                <span>1</span>
                <span>10</span>
              </div>
            </div>

            <div>
              <label className="block text-sm font-bold text-gray-700 dark:text-gray-300 mb-4">
                {t('question_types')}
              </label>
              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                {[
                  { id: 'mcq' as const, label: 'MCQ' },
                  { id: 'frq' as const, label: 'Open Ended' },
                  { id: 'matching' as const, label: 'Matching' }
                ].map((type) => (
                  <button
                    key={type.id}
                    onClick={() => toggleType(type.id)}
                    className={`py-3 px-4 rounded-xl border-2 font-medium transition-all ${
                      selectedTypes.includes(type.id)
                        ? 'border-blue-500 bg-blue-50 text-blue-600 dark:bg-blue-900/20 dark:text-blue-400'
                        : 'border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 hover:border-gray-300 dark:hover:border-gray-600'
                    }`}
                  >
                    {type.label}
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={handleStartLesson}
              className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 transition-all active:scale-95 flex items-center justify-center gap-2"
            >
              <Play size={20} fill="currentColor" />
              {t('start_lesson')}
            </button>
          </div>
        </div>
      </div>
    );
  }

  const handleMcqAnswer = (qId: string, idx: number) => {
    if (quizSubmitted) return;
    setSelectedAnswers(prev => ({ ...prev, [qId]: idx }));
  };

  const handleMatchingAnswer = (qId: string, term: string, def: string) => {
    if (quizSubmitted) return;
    setMatchingAnswers(prev => ({
      ...prev,
      [qId]: { ...(prev[qId] || {}), [term]: def }
    }));
  };

  return (
    <div className="animate-fade-in pb-20">
      <div className="flex justify-between items-center mb-6">
        <button 
          onClick={() => selectUnit(null)} 
          className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 dark:hover:text-white transition-colors"
        >
          <ArrowLeft size={16} /> {t('back')}
        </button>

        <button 
          onClick={handleRegenerate}
          className="flex items-center gap-2 px-3 py-1.5 bg-red-50 dark:bg-red-900/10 text-red-600 dark:text-red-400 rounded-lg text-xs font-semibold hover:bg-red-100 dark:hover:bg-red-900/30 transition-colors"
        >
          <RotateCcw size={12} />
          {t('regenerate')}
        </button>
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-4">
        <h1 className="text-3xl md:text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">
          {selectedUnit.title}
        </h1>
        <div className="flex bg-gray-100 dark:bg-gray-800 p-1 rounded-xl self-start">
          <button
            onClick={() => setActiveTab('learn')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'learn' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('learn')}
          </button>
          <button
            onClick={() => setActiveTab('quiz')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'quiz' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('quiz')}
          </button>
          <button
            onClick={() => setActiveTab('videos')}
            className={`px-4 py-2 rounded-lg text-sm font-medium transition-all ${
              activeTab === 'videos' 
                ? 'bg-white dark:bg-gray-700 text-gray-900 dark:text-white shadow-sm' 
                : 'text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
          >
            {t('videos')}
          </button>
        </div>
      </div>

      {activeTab === 'learn' && (
        <div className="max-w-4xl mx-auto">
          <div className="prose prose-lg dark:prose-invert max-w-none">
            <ReactMarkdown 
               components={{
                 h1: ({children}) => <h1 className="text-4xl font-extrabold mt-12 mb-6 text-gray-900 dark:text-white leading-tight">{children}</h1>,
                 h2: ({children}) => <h2 className="text-2xl font-bold mt-12 mb-6 text-gray-800 dark:text-white border-b border-gray-200 dark:border-gray-800 pb-3">{children}</h2>,
                 h3: ({children}) => <h3 className="text-xl font-bold mt-8 mb-4 text-gray-800 dark:text-gray-200">{children}</h3>,
                 p: ({children}) => <p className="text-lg leading-loose mb-6 text-gray-700 dark:text-gray-300">{children}</p>,
                 ul: ({children}) => <ul className="list-disc pl-6 mb-6 space-y-3 text-lg text-gray-700 dark:text-gray-300">{children}</ul>,
                 ol: ({children}) => <ol className="list-decimal pl-6 mb-6 space-y-3 text-lg text-gray-700 dark:text-gray-300">{children}</ol>,
                 li: ({children}) => <li className="pl-2">{children}</li>,
                 code: ({node, inline, className, children, ...props}: any) => {
                   const content = String(children).replace(/\n$/, '');
                   const isMultiLine = content.includes('\n');

                   if (inline || !isMultiLine) {
                     return (
                       <code className="bg-indigo-50 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-2 py-0.5 rounded-md text-[0.9em] font-mono border border-indigo-100 dark:border-indigo-800/50 align-middle" {...props}>
                         {children}
                       </code>
                     );
                   }
                   return (
                     <div className="my-10 rounded-2xl overflow-hidden shadow-2xl bg-[#1e1e1e] border border-gray-700/50 transform transition-transform hover:scale-[1.01] duration-300">
                       <div className="flex items-center gap-2 px-5 py-3 bg-[#2d2d2d] border-b border-gray-700/50">
                         <div className="w-3 h-3 rounded-full bg-[#ff5f56]" />
                         <div className="w-3 h-3 rounded-full bg-[#ffbd2e]" />
                         <div className="w-3 h-3 rounded-full bg-[#27c93f]" />
                         <div className="ml-auto text-xs text-gray-500 font-mono opacity-50">code</div>
                       </div>
                       <div className="p-6 overflow-x-auto">
                         <code className="font-mono text-sm text-gray-200 leading-relaxed block" {...props}>
                           {children}
                         </code>
                       </div>
                     </div>
                   );
                 },
                 blockquote: ({children}) => (
                   <blockquote className="border-l-4 border-blue-500 pl-6 py-2 my-8 italic bg-blue-50/50 dark:bg-blue-900/10 rounded-r-xl text-gray-700 dark:text-gray-300">
                     {children}
                   </blockquote>
                 )
               }}
            >
              {selectedUnit.content}
            </ReactMarkdown>
          </div>
          <div className="my-16 border-t border-gray-100 dark:border-gray-800 pt-10">
            <Flashcards />
          </div>
        </div>
      )}

      {activeTab === 'quiz' && (
        <div className="max-w-2xl mx-auto space-y-8">
          {selectedUnit.questions.length === 0 ? (
            <div className="text-center text-gray-500">No questions generated.</div>
          ) : (
             selectedUnit.questions.map((q, idx) => {
                if (q.type === 'mcq' && q.options) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <div className="space-y-3">
                        {q.options.map((opt, optIdx) => {
                          let btnClass = "w-full text-left p-4 rounded-xl border transition-all text-sm font-medium ";
                          if (quizSubmitted) {
                            if (optIdx === q.correctIndex) btnClass += "bg-green-100 border-green-500 text-green-700 dark:bg-green-900/30 dark:text-green-300 ";
                            else if (selectedAnswers[q.id] === optIdx) btnClass += "bg-red-50 border-red-200 text-red-600 dark:bg-red-900/20 dark:text-red-300 ";
                            else btnClass += "border-transparent bg-gray-50 dark:bg-gray-700/50 opacity-50 dark:text-gray-400 ";
                          } else {
                            if (selectedAnswers[q.id] === optIdx) btnClass += "border-blue-500 bg-blue-50 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300 ";
                            else btnClass += "border-transparent bg-gray-50 hover:bg-gray-100 dark:bg-gray-700/50 dark:hover:bg-gray-700 dark:text-gray-300 ";
                          }
                          return (
                            <button key={optIdx} onClick={() => handleMcqAnswer(q.id, optIdx)} className={btnClass}>
                              <div className="flex items-center justify-between">
                                {opt}
                                {quizSubmitted && optIdx === q.correctIndex && <CheckCircle size={16} className="text-green-600" />}
                                {quizSubmitted && selectedAnswers[q.id] === optIdx && optIdx !== q.correctIndex && <AlertCircle size={16} className="text-red-500" />}
                              </div>
                            </button>
                          )
                        })}
                      </div>
                    </div>
                  );
                }
                if (q.type === 'frq') {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text}
                      </h4>
                      <textarea 
                        className="w-full p-4 rounded-xl bg-gray-50 dark:bg-gray-700/50 border border-gray-200 dark:border-gray-700 focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white h-32 mb-4"
                        placeholder={t('type_message')}
                      ></textarea>
                      <button 
                        onClick={() => setShowFrqAnswers(prev => ({...prev, [q.id]: !prev[q.id]}))}
                        className="text-blue-600 dark:text-blue-400 font-semibold text-sm flex items-center gap-2 hover:underline"
                      >
                        <Eye size={16} /> {t('reveal_answer')}
                      </button>
                      {showFrqAnswers[q.id] && (
                        <div className="mt-4 p-4 bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800 rounded-xl text-green-800 dark:text-green-300 text-sm">
                          <strong>{t('model_answer')}:</strong> {q.answer}
                        </div>
                      )}
                    </div>
                  );
                }
                if (q.type === 'matching' && q.pairs) {
                  return (
                    <div key={q.id} className="bg-white dark:bg-gray-800 p-6 rounded-3xl shadow-sm border border-gray-100 dark:border-gray-700">
                      <h4 className="text-lg font-bold text-gray-900 dark:text-white mb-4">
                        <span className="text-gray-400 mr-2">{idx + 1}.</span>
                        {q.text || t('match_pairs')}
                      </h4>
                      <div className="space-y-4">
                        {q.pairs.map((pair, pIdx) => {
                          const currentAnswer = matchingAnswers[q.id]?.[pair.term];
                          const isCorrect = quizSubmitted && currentAnswer === pair.definition;

                          return (
                            <div key={pIdx} className="flex flex-col sm:flex-row sm:items-center gap-4 p-3 bg-gray-50 dark:bg-gray-700/30 rounded-xl">
                              <div className="flex-1 font-semibold text-gray-800 dark:text-gray-200">{pair.term}</div>
                              <div className="hidden sm:block text-gray-400">→</div>
                              <select 
                                value={currentAnswer || ""}
                                onChange={(e) => handleMatchingAnswer(q.id, pair.term, e.target.value)}
                                disabled={quizSubmitted}
                                className={`flex-1 p-2.5 rounded-lg border text-sm outline-none transition-colors ${
                                  quizSubmitted 
                                    ? (isCorrect 
                                        ? "bg-green-100 border-green-500 text-green-800 dark:bg-green-900/40 dark:text-green-200"
                                        : "bg-red-50 border-red-300 text-red-800 dark:bg-red-900/20 dark:text-red-200")
                                    : "bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-600 text-gray-800 dark:text-white focus:border-blue-500"
                                }`}
                              >
                                <option value="">{t('select_match')}</option>
                                {q.pairs?.map((p) => (
                                  <option key={p.definition} value={p.definition}>{p.definition}</option>
                                ))}
                              </select>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  );
                }
                return null;
            })
          )}

          <div className="sticky bottom-6 bg-white/80 dark:bg-gray-900/80 backdrop-blur-lg p-4 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-700 flex items-center justify-between">
             <div className="text-sm font-semibold text-gray-600 dark:text-gray-300">
               {quizSubmitted ? t('submit') : t('submit')}
             </div>
             <button
               onClick={submitQuiz}
               disabled={quizSubmitted || selectedUnit.questions.length === 0}
               className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100 shadow-lg shadow-blue-500/30"
             >
               {t('submit')}
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { useApp } from '../context/AppContext';
import { generateChatResponse } from '../services/geminiService';
import { ChatMessage } from '../types';
import { MessageSquare, Send, Sparkles, X, Minimize2, Maximize2 } from 'lucide-react';
import ReactMarkdown from 'react-markdown';

export const AIChat: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language, getEffectiveApiKey, isRateLimited, incrementRequestCount, setShowSettings } = useApp();
  const [isOpen, setIsOpen] = useState(false);
  const [isMinimized, setIsMinimized] = useState(false);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  const toggleChat = () => setIsOpen(!isOpen);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isOpen]);

  const handleSend = async () => {
    if (!input.trim() || loading) return;

    if (isRateLimited) {
      setShowSettings(true);
      return;
    }

    const userMsg: ChatMessage = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    const context = selectedUnit 
      ? `Course: ${selectedCourse?.name}, Unit: ${selectedUnit.title}, Content: ${selectedUnit.content.substring(0, 100)}...`
      : "General Programming";

    // Pass language and API Key to generateChatResponse
    const responseText = await generateChatResponse(getEffectiveApiKey(), messages, userMsg.text, context, language);
    incrementRequestCount();

    const botMsg: ChatMessage = { role: 'model', text: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, botMsg]);
    setLoading(false);
  };

  if (!isOpen) {
    return (
      <button 
        onClick={toggleChat}
        className="fixed bottom-6 right-6 w-14 h-14 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-full shadow-xl shadow-blue-500/40 flex items-center justify-center text-white hover:scale-110 transition-transform z-40 active:scale-95"
      >
        <Sparkles size={24} />
      </button>
    );
  }

  return (
    <div className={`fixed bottom-6 right-6 w-full md:w-[450px] bg-white dark:bg-gray-900 rounded-3xl shadow-2xl z-40 flex flex-col transition-all duration-300 border border-gray-100 dark:border-gray-800 overflow-hidden ${isMinimized ? 'h-[70px]' : 'h-[650px] max-h-[85vh]'}`}>

      {/* Header */}
      <div className="h-16 bg-white/90 dark:bg-gray-900/90 backdrop-blur-md flex items-center justify-between px-5 border-b border-gray-100 dark:border-gray-800 absolute top-0 left-0 right-0 z-10">
        <div className="flex items-center gap-2">
          <div className="w-8 h-8 rounded-full bg-indigo-100 dark:bg-indigo-900/30 flex items-center justify-center text-indigo-600 dark:text-indigo-400">
            <Sparkles size={16} />
          </div>
          <div>
            <h3 className="font-bold text-sm dark:text-white">{t('ai_tutor')}</h3>
            {!isMinimized && <p className="text-[10px] text-green-500 font-medium flex items-center gap-1"><span className="w-1.5 h-1.5 rounded-full bg-green-50 animate-pulse"/> Online</p>}
          </div>
        </div>
        <div className="flex items-center gap-1">
          <button onClick={() => setIsMinimized(!isMinimized)} className="p-2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
            {isMinimized ? <Maximize2 size={16} /> : <Minimize2 size={16} />}
          </button>
          <button onClick={toggleChat} className="p-2 text-gray-400 hover:text-red-500">
            <X size={18} />
          </button>
        </div>
      </div>

      {/* Messages */}
      {!isMinimized && (
        <>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 pt-20 pb-4 space-y-4 bg-gray-50/50 dark:bg-black/20">
            {messages.length === 0 && (
              <div className="text-center text-gray-400 mt-20 p-6">
                <MessageSquare size={48} className="mx-auto mb-4 opacity-20" />
                <p className="text-sm">{t('type_message')}</p>
              </div>
            )}
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[90%] p-4 rounded-2xl text-sm leading-relaxed shadow-sm overflow-hidden ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-br-none' 
                    : 'bg-white dark:bg-gray-800 dark:text-gray-200 border border-gray-100 dark:border-gray-700 rounded-bl-none'
                }`}>
                  <div className={`prose prose-sm dark:prose-invert max-w-none 
                      ${msg.role === 'user' ? 'prose-headings:text-white prose-p:text-white prose-strong:text-white prose-code:text-white' : ''}
                    `}>
                    <ReactMarkdown 
                      components={{
                        code: ({node, inline, className, children, ...props}: any) => {
                          // Check for multi-line content
                          const content = String(children).replace(/\n$/, '');
                          const isMultiLine = content.includes('\n');

                          if (inline || !isMultiLine) {
                            return (
                              <code className="bg-indigo-50 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-2 py-0.5 rounded-md text-[0.9em] font-mono border border-indigo-100 dark:border-indigo-800/50 align-middle" {...props}>
                                {children}
                              </code>
                            )
                          }
                          // Reuse macOS window style in chat
                          return (
                            <div className="my-2 rounded-lg overflow-hidden shadow-lg bg-[#1e1e1e] border border-gray-700/50 text-left">
                               <div className="flex items-center gap-1.5 px-3 py-2 bg-[#2d2d2d] border-b border-gray-700/50">
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#ff5f56]" />
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#ffbd2e]" />
                                 <div className="w-2.5 h-2.5 rounded-full bg-[#27c93f]" />
                               </div>
                               <div className="p-3 overflow-x-auto">
                                 <code className="font-mono text-xs text-gray-200 leading-relaxed" {...props}>
                                   {children}
                                 </code>
                               </div>
                             </div>
                          )
                        }
                      }}
                    >
                      {msg.text}
                    </ReactMarkdown>
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div className="flex justify-start">
                <div className="bg-white dark:bg-gray-800 p-3 rounded-2xl rounded-bl-none shadow-sm border border-gray-100 dark:border-gray-700">
                  <div className="flex gap-1">
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }} />
                    <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }} />
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Input */}
          <div className="p-4 bg-white dark:bg-gray-900 border-t border-gray-100 dark:border-gray-800">
            <div className="relative">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                placeholder={t('type_message')}
                className="w-full bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-white rounded-full py-3.5 pl-5 pr-12 text-sm focus:outline-none focus:ring-2 focus:ring-blue-500/50 transition-all"
              />
              <button 
                onClick={handleSend}
                disabled={!input.trim()}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-blue-600 rounded-full text-white shadow-lg shadow-blue-500/30 disabled:opacity-50 disabled:shadow-none hover:scale-105 active:scale-95 transition-all"
              >
                <Send size={16} />
              </button>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { generateFlashcardsForTopic } from '../services/geminiService';
import { Flashcard } from '../types';
import { Brain, RotateCw, ChevronLeft, ChevronRight, Wand2, X } from 'lucide-react';

export const Flashcards: React.FC = () => {
  const { t, selectedUnit, selectedCourse, language, getEffectiveApiKey, isRateLimited, incrementRequestCount, setShowSettings } = useApp();
  const [cards, setCards] = useState<Flashcard[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [loading, setLoading] = useState(false);
  const [count, setCount] = useState(5);

  const requestId = useRef<number>(0);

  const handleGenerate = async () => {
    if (!selectedUnit) return;

    if (isRateLimited) {
      setShowSettings(true);
      return;
    }

    const id = Date.now();
    requestId.current = id;
    setLoading(true);

    const topic = `${selectedCourse?.name} - ${selectedUnit.title}`;
    try {
      const generated = await generateFlashcardsForTopic(getEffectiveApiKey(), topic, language, 'Beginner', count);
      if (requestId.current === id) {
        if (generated.length > 1) incrementRequestCount();
        setCards(generated);
        setCurrentIndex(0);
        setIsFlipped(false);
        setLoading(false);
      }
    } catch (e) {
      if (requestId.current === id) {
        setLoading(false);
      }
    }
  };

  const handleCancel = () => {
    requestId.current = 0;
    setLoading(false);
  };

  if (!selectedUnit) return null;

  return (
    <div className="mt-12 mb-8">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <h3 className="text-xl font-bold dark:text-white flex items-center gap-2">
          <Brain className="text-purple-500" />
          {t('flashcards')}
        </h3>

        {cards.length === 0 && !loading && (
          <div className="flex items-center gap-2">
            <div className="flex items-center bg-gray-100 dark:bg-gray-800 rounded-lg px-2 py-1">
              <span className="text-xs font-semibold text-gray-500 dark:text-gray-400 mr-2">{t('count')}:</span>
              <input 
                type="number" 
                min="3" 
                max="10" 
                value={count} 
                onChange={(e) => setCount(Number(e.target.value))}
                className="w-12 bg-transparent text-sm font-bold text-gray-900 dark:text-white outline-none"
              />
            </div>
            <button 
              onClick={handleGenerate}
              className="flex items-center gap-2 px-4 py-2 bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-300 rounded-full font-semibold hover:bg-purple-200 dark:hover:bg-purple-900/50 transition-colors text-sm"
            >
              <Wand2 size={14} />
              {t('generate_flashcards')}
            </button>
          </div>
        )}

        {loading && (
          <button 
            onClick={handleCancel}
            className="flex items-center gap-2 px-4 py-2 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full font-semibold hover:bg-red-200 dark:hover:bg-red-900/50 transition-colors text-sm"
          >
            <X size={14} />
            {t('cancel')}
          </button>
        )}
      </div>

      {loading ? (
        <div className="h-64 flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-800/50 rounded-3xl border border-gray-100 dark:border-gray-800">
           <div className="w-10 h-10 border-4 border-purple-500 border-t-transparent rounded-full animate-spin mb-4" />
           <p className="text-gray-500 dark:text-gray-400 animate-pulse">Generating cards...</p>
        </div>
      ) : cards.length > 0 ? (
        <div className="flex flex-col items-center">
          <div 
            className="perspective-1000 w-full max-w-2xl h-80 cursor-pointer"
            onClick={() => setIsFlipped(!isFlipped)}
          >
            <div className={`relative w-full h-full transition-transform duration-500 preserve-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
              {/* Front */}
              <div className="absolute w-full h-full backface-hidden bg-white dark:bg-gray-800 rounded-3xl shadow-xl border border-gray-100 dark:border-gray-700 p-8 flex flex-col items-center justify-center text-center">
                <span className="absolute top-6 left-6 text-xs font-bold text-gray-400 uppercase tracking-wider">Question</span>
                <p className="text-2xl font-medium text-gray-900 dark:text-white leading-relaxed">
                  {cards[currentIndex].front}
                </p>
                <div className="absolute bottom-6 text-gray-400 text-sm flex items-center gap-2">
                  <RotateCw size={14} /> Click to flip
                </div>
              </div>

              {/* Back */}
              <div className="absolute w-full h-full backface-hidden bg-gradient-to-br from-purple-600 to-blue-600 rounded-3xl shadow-xl p-8 flex flex-col items-center justify-center text-center rotate-y-180 text-white">
                <span className="absolute top-6 left-6 text-xs font-bold text-white/60 uppercase tracking-wider">Answer</span>
                <p className="text-xl font-medium leading-relaxed">
                  {cards[currentIndex].back}
                </p>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-6 mt-8">
            <button 
              onClick={() => {
                setIsFlipped(false);
                setCurrentIndex(prev => (prev === 0 ? cards.length - 1 : prev - 1));
              }}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:scale-110 transition-transform"
            >
              <ChevronLeft size={20} className="dark:text-white" />
            </button>

            <span className="font-mono text-sm text-gray-500 dark:text-gray-400">
              {currentIndex + 1} / {cards.length}
            </span>

            <button 
              onClick={() => {
                setIsFlipped(false);
                setCurrentIndex(prev => (prev === cards.length - 1 ? 0 : prev + 1));
              }}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-sm border border-gray-200 dark:border-gray-700 hover:scale-110 transition-transform"
            >
              <ChevronRight size={20} className="dark:text-white" />
            </button>
          </div>
        </div>
      ) : (
        <div className="h-64 flex flex-col items-center justify-center bg-gray-50 dark:bg-gray-800/50 rounded-3xl border border-dashed border-gray-200 dark:border-gray-700">
           <div className="w-16 h-16 bg-gray-100 dark:bg-gray-800 rounded-full flex items-center justify-center text-gray-400 mb-4">
             <Brain size={24} />
           </div>
           <p className="text-gray-500 dark:text-gray-400 text-center max-w-sm px-4">
             Click "Generate Cards" to create AI-powered flashcards for this unit.
           </p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { AppProvider, useApp } from './context/AppContext';
import { Settings } from './components/Settings';
import { AIChat } from './components/AIChat';
import { UnitView } from './components/UnitView';
import { generateSyllabus } from './services/geminiService';
import { LayoutGrid, BookOpen, Settings as SettingsIcon, ChevronRight, Wand2, Sparkles, X } from 'lucide-react';

const MainContent = () => {
  const { 
    t, 
    courses,
    selectedCourse, 
    selectCourse, 
    selectedLevel, 
    selectLevel, 
    selectedUnit, 
    selectUnit,
    updateCourseUnits,
    language,
    getEffectiveApiKey,
    userApiKey,
    isRateLimited,
    incrementRequestCount,
    showSettings,
    setShowSettings
  } = useApp();

  const [syllabusFocus, setSyllabusFocus] = useState('');
  const [customSubject, setCustomSubject] = useState('');
  const [subjectError, setSubjectError] = useState(false);
  const [generatingSyllabus, setGeneratingSyllabus] = useState(false);

  // Cancellation Ref
  const syllabusRequestId = useRef<number>(0);

  // Open settings on initial app load if no API key is configured
  useEffect(() => {
    if (!userApiKey) {
      setShowSettings(true);
    }
    // We only want this to run once on mount, so we pass an empty dependency array.
    // We intentionally exclude userApiKey/setShowSettings from deps to avoid re-triggering.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Reset custom fields when course/level changes
  useEffect(() => {
    setSyllabusFocus('');
    setCustomSubject('');
    setSubjectError(false);
    setGeneratingSyllabus(false);
    syllabusRequestId.current = 0;
  }, [selectedCourse?.id, selectedLevel?.id]);

  const handleGenerateSyllabus = async () => {
    if (!selectedCourse || !selectedLevel) return;

    // Check Rate Limit
    if (isRateLimited) {
      setShowSettings(true);
      return;
    }

    let targetCourseName = selectedCourse.name;
    let targetFocus = syllabusFocus;

    if (selectedCourse.id === 'other') {
      if (!customSubject.trim()) {
        setSubjectError(true);
        return;
      }
      targetCourseName = customSubject;
    }

    const requestId = Date.now();
    syllabusRequestId.current = requestId;
    setGeneratingSyllabus(true);

    try {
      const units = await generateSyllabus(
        getEffectiveApiKey(),
        targetCourseName, 
        selectedLevel.id, 
        targetFocus || `General ${targetCourseName} concepts`,
        language
      );

      if (syllabusRequestId.current === requestId) {
        if (units.length > 0) incrementRequestCount();
        updateCourseUnits(selectedCourse.id, selectedLevel.id, units);
        setGeneratingSyllabus(false);
        setSyllabusFocus('');
        setCustomSubject('');
      }
    } catch (error) {
       if (syllabusRequestId.current === requestId) {
         setGeneratingSyllabus(false);
       }
    }
  };

  const handleCancelSyllabus = () => {
    syllabusRequestId.current = 0;
    setGeneratingSyllabus(false);
  };

  // If viewing a unit
  if (selectedUnit) {
    return (
      <div className="min-h-screen bg-white dark:bg-gray-900 transition-colors duration-300">
        <div className="max-w-5xl mx-auto px-6 py-8">
           <UnitView />
        </div>
        <AIChat />
        {showSettings && <Settings onClose={() => setShowSettings(false)} />}

        {/* Fixed Settings Button for Unit View */}
        <button 
           onClick={() => setShowSettings(true)}
           className={`fixed top-6 ${language === 'ar' ? 'left-6' : 'right-6'} p-3 bg-gray-100 dark:bg-gray-800 rounded-full hover:bg-gray-200 dark:hover:bg-gray-700 transition-colors z-30`}
        >
          <SettingsIcon size={20} className="dark:text-white" />
        </button>
      </div>
    );
  }

  // Dashboard / Navigation View
  return (
    <div className="min-h-screen bg-[#F5F5F7] dark:bg-[#121212] transition-colors duration-300 flex">
      {/* Sidebar */}
      <div className="w-80 bg-white/80 dark:bg-[#1c1c1e]/80 backdrop-blur-xl border-r border-gray-200 dark:border-gray-800 p-6 flex flex-col hidden md:flex sticky top-0 h-screen">
        <div className="flex items-center gap-3 mb-10">
          <div className="w-10 h-10 bg-gradient-to-tr from-blue-500 to-cyan-400 rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg">C</div>
          <h1 className="text-xl font-bold text-gray-800 dark:text-white tracking-tight">CodeCanvas</h1>
        </div>

        <nav className="space-y-2 flex-1">
          <button className="w-full flex items-center gap-3 px-4 py-3 bg-blue-500/10 text-blue-600 dark:text-blue-400 rounded-xl font-medium transition-colors">
            <LayoutGrid size={20} />
            {t('welcome')}
          </button>
        </nav>

        <button 
          onClick={() => setShowSettings(true)}
          className="flex items-center gap-3 px-4 py-3 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-xl font-medium transition-colors mt-auto"
        >
          <SettingsIcon size={20} />
          {t('settings')}
        </button>
      </div>

      {/* Main Area */}
      <div className="flex-1 p-6 md:p-12 overflow-y-auto">
        <div className="max-w-5xl mx-auto">

          {/* Mobile Header */}
          <div className="flex md:hidden justify-between items-center mb-8">
             <h1 className="text-xl font-bold dark:text-white">CodeCanvas</h1>
             <button onClick={() => setShowSettings(true)} className="p-2 dark:text-white"><SettingsIcon /></button>
          </div>

          {!selectedCourse ? (
             <>
               <h2 className="text-4xl font-extrabold text-gray-900 dark:text-white mb-2 tracking-tight">{t('welcome')}</h2>
               <p className="text-gray-500 dark:text-gray-400 mb-10 text-lg">{t('continue_learning')}</p>

               <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                 {courses.map(course => (
                   <button
                     key={course.id}
                     onClick={() => selectCourse(course)}
                     className="group bg-white dark:bg-[#1c1c1e] p-6 rounded-3xl shadow-sm hover:shadow-2xl hover:scale-[1.02] transition-all duration-300 border border-gray-100 dark:border-gray-800 text-left"
                   >
                     <div className="w-14 h-14 bg-gray-50 dark:bg-gray-700 rounded-2xl flex items-center justify-center text-3xl mb-4 group-hover:scale-110 transition-transform">
                       {course.icon}
                     </div>
                     <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-2">{t(`course_${course.id}`) || course.name}</h3>
                     <p className="text-sm text-gray-500 dark:text-gray-400 leading-relaxed">{t(`desc_${course.id}`)}</p>
                   </button>
                 ))}
               </div>
             </>
          ) : !selectedLevel ? (
            <>
              <button onClick={() => selectCourse(null)} className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 transition-colors">
                <ChevronRight size={16} className={`rotate-180 ${language === 'ar' ? 'rotate-0' : ''}`} /> {t('back')}
              </button>
              <div className="flex items-center gap-4 mb-8">
                <span className="text-4xl">{selectedCourse.icon}</span>
                <h2 className="text-4xl font-extrabold text-gray-900 dark:text-white tracking-tight">{t(`course_${selectedCourse.id}`) || selectedCourse.name}</h2>
              </div>

              <div className="space-y-4">
                {selectedCourse.levels.map(level => (
                  <button
                    key={level.id}
                    onClick={() => selectLevel(level)}
                    className="w-full bg-white dark:bg-[#1c1c1e] p-6 rounded-3xl shadow-sm hover:shadow-md transition-all border border-gray-100 dark:border-gray-800 flex items-center justify-between group"
                  >
                    <div>
                      <h4 className="text-xl font-bold text-gray-900 dark:text-white mb-1 group-hover:text-blue-600 transition-colors">{t(`level_${level.id.substring(0,3)}`) || level.title}</h4>
                      <p className="text-sm text-gray-500">{level.units.length > 0 ? `${level.units.length} ${t('units_created')}` : t('create_custom_syllabus')}</p>
                    </div>
                    <div className="w-10 h-10 rounded-full bg-gray-100 dark:bg-gray-800 flex items-center justify-center text-gray-400 group-hover:bg-blue-600 group-hover:text-white transition-all">
                      <ChevronRight size={20} className={language === 'ar' ? 'rotate-180' : ''} />
                    </div>
                  </button>
                ))}
              </div>
            </>
          ) : (
            <>
               <button onClick={() => selectLevel(null)} className="mb-6 flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-gray-900 dark:text-gray-400 transition-colors">
                <ChevronRight size={16} className={`rotate-180 ${language === 'ar' ? 'rotate-0' : ''}`} /> {t('back')}
              </button>
              <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-2 tracking-tight">{t(`level_${selectedLevel.id.substring(0,3)}`)}</h2>
              <p className="text-gray-500 mb-8">{t('select_unit_prompt')}</p>

              <div className="grid gap-4">
                {selectedLevel.units.length > 0 ? (
                  <>
                    {selectedLevel.units.map((unit, idx) => (
                      <button
                        key={unit.id}
                        onClick={() => selectUnit(unit)}
                        className="bg-white dark:bg-[#1c1c1e] p-5 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-800 flex items-center gap-4 hover:bg-gray-50 dark:hover:bg-gray-800 transition-colors text-left"
                      >
                        <span className="w-8 h-8 rounded-lg bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 flex items-center justify-center font-bold text-sm">
                          {idx + 1}
                        </span>
                        <span className="font-semibold text-gray-900 dark:text-white flex-1">{unit.title}</span>
                        <BookOpen size={18} className="text-gray-400" />
                      </button>
                    ))}
                    <button 
                       onClick={() => updateCourseUnits(selectedCourse.id, selectedLevel.id, [])}
                       className="mt-6 text-sm text-red-500 hover:underline"
                    >
                      {t('reset_syllabus')}
                    </button>
                  </>
                ) : (
                  <div className="bg-white dark:bg-[#1c1c1e] rounded-3xl p-8 border border-gray-200 dark:border-gray-800 text-center">
                    <div className="w-16 h-16 bg-blue-50 dark:bg-blue-900/20 rounded-full flex items-center justify-center mx-auto mb-6 text-blue-600">
                      <Wand2 size={32} />
                    </div>
                    <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-2">{t('design_path')}</h3>
                    <p className="text-gray-500 dark:text-gray-400 mb-8 max-w-md mx-auto">
                      {selectedCourse.id === 'other' ? t('other_prompt_desc') : t('tell_ai')}
                    </p>

                    <div className="max-w-md mx-auto space-y-4">
                      {selectedCourse.id === 'other' ? (
                        <>
                          <div className="text-left">
                            <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 ml-1">
                                {t('subject_label')} <span className="text-red-500">*</span>
                            </label>
                            <input 
                              type="text" 
                              value={customSubject}
                              onChange={(e) => { setCustomSubject(e.target.value); setSubjectError(false); }}
                              placeholder={t('subject_placeholder')}
                              className={`w-full px-5 py-4 rounded-xl bg-gray-50 dark:bg-gray-800 border-2 ${subjectError ? 'border-red-500 focus:ring-red-500' : 'border-transparent focus:ring-blue-500'} focus:ring-2 outline-none text-gray-900 dark:text-white transition-all`}
                            />
                            {subjectError && <p className="text-red-500 text-xs mt-1 ml-1">This field is required</p>}
                          </div>

                          <div className="text-left">
                            <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2 ml-1">
                                {t('focus_label')} <span className="text-gray-400 font-normal text-xs">({t('optional')})</span>
                            </label>
                            <input 
                              type="text" 
                              value={syllabusFocus}
                              onChange={(e) => setSyllabusFocus(e.target.value)}
                              placeholder={t('focus_placeholder')}
                              className="w-full px-5 py-4 rounded-xl bg-gray-50 dark:bg-gray-800 border-2 border-transparent focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white"
                            />
                          </div>
                        </>
                      ) : (
                        <input 
                          type="text" 
                          value={syllabusFocus}
                          onChange={(e) => setSyllabusFocus(e.target.value)}
                          placeholder="E.g. Web scraping, APIs..."
                          className="w-full px-5 py-4 rounded-xl bg-gray-50 dark:bg-gray-800 border-2 border-transparent focus:ring-2 focus:ring-blue-500 outline-none text-gray-900 dark:text-white"
                        />
                      )}

                      {generatingSyllabus ? (
                        <button 
                          onClick={handleCancelSyllabus}
                          className="w-full py-4 bg-red-100 hover:bg-red-200 text-red-600 dark:bg-red-900/30 dark:hover:bg-red-900/50 dark:text-red-400 rounded-xl font-bold transition-all flex items-center justify-center gap-2"
                        >
                          <X size={20} />
                          {t('cancel')}
                        </button>
                      ) : (
                        <button 
                          onClick={handleGenerateSyllabus}
                          disabled={generatingSyllabus}
                          className="w-full py-4 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-bold shadow-lg shadow-blue-500/30 transition-all active:scale-95 disabled:opacity-70 flex items-center justify-center gap-2"
                        >
                          <Sparkles size={20} />
                          {t('generate_syllabus')}
                        </button>
                      )}
                    </div>
                  </div>
                )}
              </div>
            </>
          )}
        </div>
      </div>

      <AIChat />
      {showSettings && <Settings onClose={() => setShowSettings(false)} />}
    </div>
  );
};

export default function App() {
  return (
    <AppProvider>
      <MainContent />
    </AppProvider>
  );
}

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { AppTheme, LanguageCode, Course, Level, Unit } from '../types';
import { UI_TEXT, COURSES as DEFAULT_COURSES } from '../constants';

interface AppContextType {
  theme: AppTheme;
  toggleTheme: () => void;
  language: LanguageCode;
  setLanguage: (lang: LanguageCode) => void;
  t: (key: string) => string;
  courses: Course[];
  updateCourseUnits: (courseId: string, levelId: string, units: Unit[]) => void;
  updateUnitContent: (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => void;
  selectedCourse: Course | null;
  selectCourse: (course: Course | null) => void;
  selectedLevel: Level | null;
  selectLevel: (level: Level | null) => void;
  selectedUnit: Unit | null;
  selectUnit: (unit: Unit | null) => void;

  // API Key
  userApiKey: string;
  setUserApiKey: (key: string) => void;

  // UI State
  showSettings: boolean;
  setShowSettings: (show: boolean) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [theme, setTheme] = useState<AppTheme>('dark');
  const [language, setLanguage] = useState<LanguageCode>('en');
  const [showSettings, setShowSettings] = useState(false);

  // Local state copy of courses to allow mutation (adding generated content)
  const [courses, setCourses] = useState<Course[]>(DEFAULT_COURSES);

  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [selectedLevelId, setSelectedLevelId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | null>(null);

  // API Key State - Only allow user provided keys
  const [userApiKey, setUserApiKeyState] = useState(localStorage.getItem('user_api_key') || '');

  // Apply theme to html element
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Apply direction for RTL languages
  useEffect(() => {
    document.documentElement.dir = language === 'ar' ? 'rtl' : 'ltr';
    document.documentElement.lang = language;
  }, [language]);

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const t = (key: string): string => {
    const entry = UI_TEXT[key];
    if (!entry) return key;
    return entry[language] || entry['en'];
  };

  const setUserApiKey = (key: string) => {
    setUserApiKeyState(key);
    localStorage.setItem('user_api_key', key);
  };

  // Helper getters
  const selectedCourse = courses.find(c => c.id === selectedCourseId) || null;
  const selectedLevel = selectedCourse?.levels.find(l => l.id === selectedLevelId) || null;
  const selectedUnit = selectedLevel?.units.find(u => u.id === selectedUnitId) || null;

  const updateCourseUnits = (courseId: string, levelId: string, units: Unit[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return { ...l, units };
        })
      };
    }));
  };

  const updateUnitContent = (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return {
            ...l,
            units: l.units.map(u => {
              if (u.id !== unitId) return u;
              return { ...u, content, questions };
            })
          };
        })
      };
    }));
  };

  return (
    <AppContext.Provider value={{
      theme,
      toggleTheme,
      language,
      setLanguage,
      t,
      courses,
      updateCourseUnits,
      updateUnitContent,
      selectedCourse,
      selectCourse: (c) => { 
        setSelectedCourseId(c ? c.id : null); 
        setSelectedLevelId(null); 
        setSelectedUnitId(null); 
      },
      selectedLevel,
      selectLevel: (l) => { 
        setSelectedLevelId(l ? l.id : null); 
        setSelectedUnitId(null); 
      },
      selectedUnit,
      selectUnit: (u) => setSelectedUnitId(u ? u.id : null),

      userApiKey,
      setUserApiKey,

      showSettings,
      setShowSettings
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

