                  }`}
                >
                  <span>{lang.label}</span>
                  {language === lang.code && <div className="w-2 h-2 bg-white rounded-full" />}
                </button>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { supabase } from '../lib/supabase';
import { encryptKey, decryptKey } from '../lib/crypto';
import { AppTheme, LanguageCode, Course, Level, Unit } from '../types';
import { UI_TEXT, COURSES as DEFAULT_COURSES } from '../constants';

interface AppContextType {
  theme: AppTheme;
  toggleTheme: () => void;
  language: LanguageCode;
  setLanguage: (lang: LanguageCode) => void;
  t: (key: string) => string;
  courses: Course[];
  updateCourseUnits: (courseId: string, levelId: string, units: Unit[]) => void;
  updateUnitContent: (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => void;
  selectedCourse: Course | null;
  selectCourse: (course: Course | null) => void;
  selectedLevel: Level | null;
  selectLevel: (level: Level | null) => void;
  selectedUnit: Unit | null;
  selectUnit: (unit: Unit | null) => void;

  // Auth & API Key
  userApiKey: string;
  hasApiKey: boolean; // Source of truth from DB
  setUserApiKey: (key: string) => Promise<void>;
  session: any;
  loadingSession: boolean;
  signOut: () => Promise<void>;

  // UI State
  showSettings: boolean;
  setShowSettings: (show: boolean) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // STRICT REQUIREMENT: Dark mode must be default.
  const [theme, setTheme] = useState<AppTheme>('dark');
  const [language, setLanguage] = useState<LanguageCode>('en');
  const [showSettings, setShowSettings] = useState(false);

  // Auth State
  const [session, setSession] = useState<any>(null);
  const [loadingSession, setLoadingSession] = useState(true);

  // API Key State
  const [userApiKey, setUserApiKeyState] = useState('');
  const [hasApiKey, setHasApiKey] = useState(false); // Default to false until proven otherwise

  // Local state copy of courses
  const [courses, setCourses] = useState<Course[]>(DEFAULT_COURSES);
  const [selectedCourseId, setSelectedCourseId] = useState<string | null>(null);
  const [selectedLevelId, setSelectedLevelId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | null>(null);

  // Force Dark Mode on Mount
  useEffect(() => {
    document.documentElement.classList.add('dark');
    setTheme('dark');
  }, []);

  // Theme Toggle
  useEffect(() => {
    if (theme === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [theme]);

  // Auth & Profile Sync
  useEffect(() => {
    let mounted = true;

    // 1. SAFETY TIMEOUT: 
    // If Supabase hangs (common with stale local storage), force app to load after 2 seconds.
    // This prevents the "infinite loading screen" requiring localStorage.clear().
    const safetyTimeout = setTimeout(() => {
      if (mounted && loadingSession) {
        console.warn("Session loading timed out. Forcing app render.");
        setLoadingSession(false);
      }
    }, 2000);

    const initAuth = async () => {
      try {
        const { data: { session: currentSession }, error } = await supabase.auth.getSession();

        if (error) throw error;

        if (mounted) {
          if (currentSession) {
            setSession(currentSession);
            // Fetch profile in background, don't block UI if it fails
            fetchProfile(currentSession.user.id).catch(err => console.error("Profile sync failed", err));
          } else {
            setLoadingSession(false);
          }
        }
      } catch (err) {
        console.error("Auth init error:", err);
        if (mounted) setLoadingSession(false);
      }
    };

    initAuth();

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, newSession) => {
      if (!mounted) return;

      if (event === 'SIGNED_OUT') {
        setSession(null);
        setUserApiKeyState('');
        setHasApiKey(false);
        setLoadingSession(false);
      } else if (newSession) {
        setSession(newSession);
        // On initial sign-in, try to fetch the profile
        if (event === 'SIGNED_IN') {
           await fetchProfile(newSession.user.id);
        }
        setLoadingSession(false);
      }
    });

    return () => {
      mounted = false;
      clearTimeout(safetyTimeout);
      subscription.unsubscribe();
    };
  }, []);

  // Fetch Profile
  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('api_key_encrypted, has_api_key')
        .eq('id', userId)
        .maybeSingle();

      if (error) {
        console.warn('Profile fetch warning:', error.message);
        return;
      }

      if (data) {
        setHasApiKey(data.has_api_key);
        if (data.api_key_encrypted) {
          const decrypted = decryptKey(data.api_key_encrypted);
          if (decrypted) setUserApiKeyState(decrypted);
        }
      }
    } catch (error) {
      console.error('Error in fetchProfile:', error);
    } finally {
      setLoadingSession(false);
    }
  };

  // Secure Save Logic
  const saveUserKey = async (key: string) => {
    // 1. OPTIMISTIC UPDATE:
    // Update local state IMMEDIATELY. This allows the user to generate content 
    // right now, even if the database save fails (e.g., due to network/permissions).
    setUserApiKeyState(key);
    setHasApiKey(true);

    if (!session) return;

    try {
      const encrypted = encryptKey(key);
      const userId = session.user.id;

      // 2. Cloud Save
      // Using UPSERT with specific conflict handling to fix "works once then fails"
      const { error } = await supabase
        .from('profiles')
        .upsert({ 
          id: userId, 
          email: session.user.email,
          api_key_encrypted: encrypted,
          has_api_key: true,
          updated_at: new Date().toISOString()
        }, { onConflict: 'id' });

      if (error) throw error;

    } catch (error: any) {
      console.error('Cloud save failed:', error);
      // We throw the error so Settings.tsx can show a warning (yellow alert),
      // BUT we do NOT revert the local state. The user can still work in this session.
      throw new Error(error.message || 'Database connection failed');
    }
  };

  const signOut = async () => {
    try {
      await supabase.auth.signOut();
    } catch (e) {
      console.error("Sign out error", e);
    }
    setUserApiKeyState('');
    setHasApiKey(false);
    setSession(null);
  };

  const toggleTheme = () => {
    setTheme(prev => prev === 'light' ? 'dark' : 'light');
  };

  const t = (key: string): string => {
    const entry = UI_TEXT[key];
    if (!entry) return key;
    return entry[language] || entry['en'];
  };

  const updateCourseUnits = (courseId: string, levelId: string, units: Unit[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return { ...l, units };
        })
      };
    }));
  };

  const updateUnitContent = (courseId: string, levelId: string, unitId: string, content: string, questions: any[]) => {
    setCourses(prev => prev.map(c => {
      if (c.id !== courseId) return c;
      return {
        ...c,
        levels: c.levels.map(l => {
          if (l.id !== levelId) return l;
          return {
            ...l,
            units: l.units.map(u => {
              if (u.id !== unitId) return u;
              return { ...u, content, questions };
            })
          };
        })
      };
    }));
  };

  // Helper getters
  const selectedCourse = courses.find(c => c.id === selectedCourseId) || null;
  const selectedLevel = selectedCourse?.levels.find(l => l.id === selectedLevelId) || null;
  const selectedUnit = selectedLevel?.units.find(u => u.id === selectedUnitId) || null;

  return (
    <AppContext.Provider value={{
      theme,
      toggleTheme,
      language,
      setLanguage,
      t,
      courses,
      updateCourseUnits,
      updateUnitContent,
      selectedCourse,
      selectCourse: (c) => { 
        setSelectedCourseId(c ? c.id : null); 
        setSelectedLevelId(null); 
        setSelectedUnitId(null); 
      },
      selectedLevel,
      selectLevel: (l) => { 
        setSelectedLevelId(l ? l.id : null); 
        setSelectedUnitId(null); 
      },
      selectedUnit,
      selectUnit: (u) => setSelectedUnitId(u ? u.id : null),

      userApiKey,
      hasApiKey,
      setUserApiKey: saveUserKey,
      session,
      loadingSession,
      signOut,

      showSettings,
      setShowSettings
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};
